BEGIN;
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0694', 'The Expert Bottleneck', '3d-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'You are training a Mixture-of-Experts (MoE) model. During a fine-tuning run on Python code, you notice your training throughput drops by 8x. Based on the router diagram, what is causing the massive compute starvation on the other GPUs?', 'Based on the router diagram, what is causing the massive compute starvation on the other GPUs?', '"Just add more GPUs for Expert 2." You can''t dynamically clone model weights to new GPUs at the microsecond timescale of a forward pass without massive overhead.', 'Expert 2 has hit its **Capacity Limit**. In MoE, frameworks pre-allocate a fixed capacity per expert. When a prompt is domain-specific (like code), the router sends nearly all tokens to one expert. That expert becomes a bottleneck, forcing the system to either drop tokens or serialize execution, leaving the other expert GPUs idle. The fix is **Expert Replication** (cloning hot experts) or using an **Auxiliary Load-Balancing Loss** during training.', 'If 8 experts each have a capacity of $C$ tokens, but one expert receives $8C$ tokens, that expert takes 8x longer to compute while the other 7 GPUs sit at 0% utilization for 87.5% of the step time.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0694.yaml', '734f8beceeebcbb6341de9b340b349ad9e9d767fa3fdaf67bdab03cf6f3cdbf2', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0712', 'The Multi-GPU Scaling Curve', '3d-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'You scale a training job from 1 to 2, 4, 8, 16, and 32 H100 GPUs using data parallelism. At 1 GPU, throughput is 1,000 samples/sec. Predict the throughput at each scale, accounting for communication overhead. The interconnect is NVLink within 8-GPU nodes and InfiniBand (400 Gb/s) between nodes.', 'What throughput do you predict at 1, 2, 4, 8, 16, and 32 H100 GPUs with NVLink inside nodes and 400 Gb/s InfiniBand between nodes?', '"Linear scaling — 32 GPUs = 32,000 samples/sec." This ignores that communication overhead grows with GPU count and that crossing the node boundary (NVLink → InfiniBand) causes a discontinuous drop in scaling efficiency.', 'Scaling efficiency = actual throughput / (N × single-GPU throughput). Within a node (NVLink), AllReduce is fast and overlaps well with compute. Across nodes (InfiniBand), bandwidth drops ~18× and latency increases, creating a scaling cliff at the node boundary.', 'Model: 7B params, 14 GB gradients (FP16). Single-GPU step: 100 ms compute. **Intra-node (NVLink 900 GB/s):** AllReduce time for $N$ GPUs: $2(N-1)/N \times 14\text{GB} / 900\text{GB/s}$ (bus bandwidth). 2 GPUs: 15.6 ms. 4 GPUs: 23.3 ms. 8 GPUs: 27.2 ms. With overlap: ~30% exposed. Effective overhead: 2→4.7ms, 4→7ms, 8→8.2ms. Throughput (N × 1000 × 100 / (100+overhead)): 2→1,910 (95.5%), 4→3,738 (93.5%), 8→7,393 (92.4%). **Inter-node (InfiniBand 50 GB/s effective):** 16 GPUs (2 nodes): AllReduce across nodes: 14 GB / 50 GB/s = 280 ms — longer than compute! Must use hierarchical AllReduce: intra-node (8.2 ms) + inter-node of reduced gradients (28 ms) = 36.2 ms exposed. Throughput: 16→11,747 (73.4%). **The NVLink→InfiniBand boundary at GPU 9 causes scaling to drop significantly.**', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0712.yaml', '4e4281ebb978bb50bea7e88e9c11f4cfa7cb825ac214fdf456354c7d73339921', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0769', 'The Bad Batch Spike', '3d-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You''re fine-tuning a 7B model on 8 A100 GPUs. At step 12,400 the training loss suddenly spikes from 1.8 to 45.0, then gradually recovers over the next 200 steps. The spike happens at the exact same step every time you restart from the same checkpoint. What''s in that batch, and how do you prove it?', 'What''s in that batch, and how do you prove it?', '"The learning rate is too high — reduce it" or "This is normal training noise." The reproducibility at the exact same step rules out stochastic noise, and the spike magnitude (25×) is far beyond normal gradient variance.', 'The deterministic reproduction at step 12,400 means the data loader, with its fixed seed, serves a specific mini-batch at that step that contains pathological examples. Common culprits: (1) a corrupted sample with extremely long repetitive sequences that cause attention to produce near-uniform distributions, generating huge gradients in the softmax backward pass; (2) a mislabeled example where the target is nonsensical (e.g., a truncated UTF-8 sequence decoded as garbage tokens), producing a cross-entropy loss orders of magnitude above normal; (3) a duplicate of the prompt as the target, causing the model to receive contradictory supervision. Proof: log the batch indices at step 12,400, extract those samples, compute per-sample loss — the pathological sample will have loss >100× the batch mean. Fix: implement per-sample gradient clipping or loss clipping that caps individual sample contributions, and add a data quality filter that removes samples with anomalous token distributions.', 'Normal per-sample cross-entropy loss ≈ 1.8 nats (averaged over tokens). A garbage-target sample where the model assigns ~0.001 probability to each target token: per-token loss = $-\ln(0.001) = 6.9$ nats. With standard PyTorch `CrossEntropyLoss(reduction=''mean'')`, loss is averaged over all tokens across the batch. Batch: 32 samples × 512 tokens = 16,384 tokens total. Good tokens: 31 × 512 = 15,872 tokens at 1.8 nats each. Bad tokens: 512 tokens at 6.9 nats each. Batch mean = $(15,872 \times 1.8 + 512 \times 6.9) / 16,384 = (28,570 + 3,533) / 16,384 ≈ $ **1.96 nats** — barely noticeable. To produce a spike to 45.0, the loss must use `reduction=''sum''` or the sample is far more pathological: e.g., a truncated sequence decoded as out-of-vocabulary garbage where the model assigns ~$e^{-45}$ probability per token, producing per-token loss of ~45 nats. With per-sample sum reported as batch loss: one sample with 512 × 45 = 23,040 nats dominates the batch sum. The gradient norm from this sample is ~$45/1.8 = 25\times$ normal per-token, and concentrated in the embedding/output layers for the garbage tokens. Without per-sample gradient clipping, this single sample''s gradient dominates the entire update, pushing all 7B parameters in a nonsensical direction. Recovery takes ~200 steps because the learning rate is small enough that 200 normal updates gradually undo the damage.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0769.yaml', '221247fd00d002f2a3c8342f2939f01e959acf05f69402707d0bbea73734e885', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0770', 'The DataLoader Deadlock', '3d-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'Your training job on 8 A100 GPUs hangs at step 1 and never progresses. GPU utilization is 0%. CPU utilization is 100% across all cores. `htop` shows 128 Python processes in `D` (uninterruptible sleep) state. You set `num_workers=16` per GPU in the DataLoader. What happened, and what''s the maximum safe value for `num_workers`?', 'What happened, and what''s the maximum safe value for `num_workers`?', '"More workers means faster data loading — set it as high as possible" or "The dataset is too large to fit in memory." The first ignores system resource limits, and the second is unrelated to the deadlock.', 'You''ve created 128 worker processes (16 per GPU × 8 GPUs) that are all competing for shared resources and deadlocking. The `D` state means they''re waiting on I/O or kernel locks. Three mechanisms cause this: (1) **Shared memory exhaustion** — each DataLoader worker uses shared memory (`/dev/shm`) to pass tensors to the main process. Default `/dev/shm` in Docker is 64 MB. With 128 workers each trying to write a batch (e.g., 32 images × 224×224×3 × 4 bytes = 19 MB per batch): total demand = $128 \times 19\text{ MB} = 2.4\text{ GB}$ — far exceeding 64 MB. Workers block on `shm_open()`. (2) **File descriptor exhaustion** — each worker opens dataset files. At 128 workers with 10 FDs each: 1,280 FDs, potentially exceeding the process limit (default 1024). (3) **CPU oversubscription** — 128 CPU-bound workers on a 64-core machine means 2× oversubscription, causing context-switch thrashing. Fix: set `num_workers = min(cpu_cores / num_gpus, 4)` as a starting point. For 64 cores and 8 GPUs: `num_workers=8`. Increase `/dev/shm` to 16 GB in Docker (`--shm-size=16g`).', 'Server: 64 CPU cores, 512 GB RAM, 8 GPUs. `num_workers=16` per GPU × 8 GPUs = **128 workers**. CPU oversubscription: $128 / 64 = 2\times$ — each worker gets only 50% of a core, and context-switching overhead wastes ~30% of that. Effective CPU per worker: **35%**. Shared memory: 128 workers × 19 MB/batch = **2.4 GB** needed. Docker default `/dev/shm` = 64 MB → **37× oversubscribed** → deadlock. File descriptors: 128 × 10 = 1,280 FDs. `ulimit -n` default = 1024 → **exceeded** → workers fail on `open()`. Safe configuration: `num_workers=4` per GPU × 8 GPUs = 32 workers. CPU utilization: $32/64 = 50\%$ — leaves headroom for the main process and system tasks. Shared memory: $32 \times 19 = 608\text{ MB}$ — set `--shm-size=2g` for safety. Data loading throughput at 4 workers: ~**3,200 images/s** per GPU (sufficient for most training at batch_size=32 with augmentation).', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0770.yaml', '26e59289109d1681eae8d69dcadaa8bbabe2453491c925b51c464cc4fd5c5890', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0774', 'The Optimizer State Explosion', '3d-parallelism', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'training', 'published', 'A junior engineer is fine-tuning a 7B model on a single A100 80 GB. They report: ''The model is only 14 GB in FP16, but training OOMs at batch_size=1. How can a 14 GB model not fit on an 80 GB GPU?'' Walk them through where the other 66 GB went.', 'Where did the other 66 GB of GPU memory go during full fine-tuning?', '"The model must be loading in FP32 — that''s 28 GB" or "The batch size is too large." Even FP32 weights are only 28 GB, and they said batch_size=1. The real memory consumer is invisible in `model.parameters()`.', 'The Adam optimizer stores *two additional copies* of every parameter: the first moment (mean of gradients, $m_t$) and the second moment (variance of gradients, $v_t$), both in FP32. Combined with the FP32 master copy of weights (needed for mixed-precision training), the optimizer state is the dominant memory consumer. The full breakdown: (1) FP16 model weights: 7B × 2 = **14 GB**; (2) FP32 master weights (for optimizer update): 7B × 4 = **28 GB**; (3) FP32 gradients: 7B × 4 = **28 GB**; (4) FP32 Adam $m$: 7B × 4 = **28 GB**; (5) FP32 Adam $v$: 7B × 4 = **28 GB**. Total: **126 GB** — 1.6× the GPU''s memory, and we haven''t even counted activations. The 14 GB model "expands" to 126 GB during training because the optimizer needs 16 bytes per parameter (FP16 weight + FP32 master + FP32 grad + FP32 m + FP32 v = 2 + 4 + 4 + 4 + 4 = 18 bytes, but the FP16 weight is a view of the FP32 master, so effectively 16 bytes of *additional* state). Fix: use LoRA (only optimize ~0.1% of parameters), 8-bit Adam (halves optimizer state), or gradient checkpointing + CPU offloading.', '**Full fine-tuning memory:** FP16 weights: **14 GB**. FP32 master weights: **28 GB**. FP32 gradients: **28 GB**. Adam $m_t$ (FP32): **28 GB**. Adam $v_t$ (FP32): **28 GB**. Activations (batch=1, seq=2048, 32 layers): ~**4 GB**. CUDA workspace + fragmentation: ~**2 GB**. **Total: ~132 GB** on an 80 GB GPU → **OOM**. **LoRA (rank=16) memory:** Trainable params: $2 \times 32 \times 2 \times 4096 \times 16 = $ 8.4M (0.12% of 7B). LoRA optimizer state: 8.4M × 12 bytes = **101 MB**. Frozen FP16 weights: **14 GB**. Activations: **4 GB**. **Total: ~18.1 GB** — fits on 80 GB with room for batch_size=16. The optimizer state went from 84 GB to 101 MB — a **830× reduction**.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0774.yaml', '4a92c0c06fd94435185d06d08609a9ef11fcf13aaacbc86a09cfaa08763a42b8', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1086', 'Scaling Data Parallelism: Ethernet vs InfiniBand', 'data-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'You are scaling the training of a 300M parameter model (approx 1.2GB in FP32) across a 128-node cluster (8x A100 80GB GPUs per node). The cross-node interconnect is standard 100 Gbps Ethernet, while intra-node is NVLink. A proposal is on the table to upgrade the cross-node network to 400 Gbps InfiniBand to improve training efficiency. Evaluate the standard Data Parallelism communication overhead and justify whether the costly InfiniBand upgrade is mathematically necessary to avoid network bottlenecks, assuming a compute time of 150ms per batch step.', 'Is the 400 Gbps InfiniBand upgrade necessary for 128-node data-parallel training, given 150ms compute per step?', 'Candidates often look only at the high intra-node NVLink bandwidth and ignore the cross-node Ethernet bottleneck in the Ring AllReduce logical ring, failing to recognize that the slowest link determines the entire ring''s throughput.', 'Calculate the AllReduce time using the 100 Gbps (12.5 GB/s) cross-node bottleneck. Because the logical ring must traverse the slowest link, the 192ms communication time exceeds the 150ms compute time, making the system network-bound. Upgrading to 400 Gbps (50 GB/s) reduces communication time to 48ms, fully hiding it behind the 150ms compute and unblocking the scaling.', 'Ring AllReduce data transferred per GPU = 2 * (N-1)/N * Model_Size ≈ 2 * 1 * 1.2GB = 2.4GB. Cross-node bandwidth = 100 Gbps = 12.5 GB/s. Communication time = 2.4GB / 12.5GB/s = 192ms. Since Comm time (192ms) > Compute time (150ms), the system is network-bound. Upgrading to 400 Gbps (50 GB/s) reduces Comm time to 48ms, fully unblocking the compute.', 'imported', '2026-03-23T21:44:46.750106', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1086.yaml', 'bb89ff49b2f80853c94ece553aa77f8d9dfe2499235df9b7d4d416aeb7941f7e', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1845', 'Diagnosing GPU Underutilization in Long-Sequence RNNs', 'data-parallelism', 'cloud', 'L4', 'optimization', 'parallelism', 'analyze', 'training', 'published', 'Your team is deploying a multi-layer LSTM for high-frequency trading anomaly detection on an NVIDIA A100 (312 TFLOPs FP16). The input time-series has a sequence length of 2048. Despite heavily optimizing the data pipeline and increasing the batch size to 256, the GPU SM utilization hovers around 15%, and inference latency is unacceptably high at over 45ms per batch. Profiling shows that tensor core usage is negligible. Diagnose the architectural bottleneck causing this poor hardware utilization.', 'What architectural bottleneck is causing low A100 utilization and >45ms latency for the 2048-step LSTM?', 'Assuming the bottleneck is purely I/O, memory bandwidth, or suboptimal kernel launch overhead, rather than an inherent, unfixable architectural constraint.', 'Identify the O(N) sequential dependency where hidden state computation at time t strictly requires the output from time t-1. This serial execution path prevents the GPU from parallelizing matrix operations across the sequence dimension, leaving massively parallel SMs idle. The architectural solution requires migrating to models that allow parallel computation across time (like Transformers or Temporal Convolutional Networks).', 'An A100 executes ~3.12e14 FP16 FLOPs/sec. For a single sequence step of an LSTM (hidden size 512, batch 256), the math is ~8 * 256 * 512^2 = ~5.3e8 FLOPs. Over 2048 steps, that''s ~1.1e12 FLOPs total. If perfectly parallelized, it would take 1.1e12 / 3.12e14 = ~3.5ms. But serialized across 2048 steps, kernel launch and sequential scheduling latencies (e.g., ~15us per step) dominate: 2048 * 15us = ~30ms latency minimum just from step-by-step execution boundaries, mathematically capping utilization.', 'imported', '2026-03-24T00:55:56.784092', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1845.yaml', '9efde82ee4dec9e95a207cd251222dc815807af06c2def63e87be357f0c9ffcd', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2215', 'The Utilization vs Job Completion Time Paradox', 'data-parallelism', 'cloud', 'L4', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'Your cluster dashboard proudly shows 95% GPU utilization. But ML engineers are furious — their training jobs take 3x longer to complete than the raw compute time suggests. The VP of Infrastructure says ''We''re running the cluster hot, that''s efficient.'' The VP of ML says ''My team is blocked and we''re burning money on idle engineer time.'' Who is right, and what is the fundamental tradeoff the cluster is hitting?', 'Who is right, and what is the fundamental tradeoff the cluster is hitting?', 'Siding entirely with one VP. High utilization IS efficient from an infrastructure cost perspective. But utilization is not the right metric for ML productivity. The cluster is in the queueing theory ''hockey stick'' zone.', 'Both are partially right, but the VP of ML is more right at the margin. This is the classic utilization-delay tradeoff from queueing theory. When a system operates above ~80% utilization, queueing delays grow non-linearly (M/M/1: $W = \frac{1}{\mu(1-\rho)}$). At 95% utilization, average wait time is 19x the service time. The correct metric is not utilization alone but *goodput* — useful work completed per unit time. High utilization with long queue times means engineers wait days for experiments, slowing the entire ML development cycle. The resolution: implement priority tiers. Reserve 70-80% capacity for guaranteed-SLA jobs (fast queue), use the remaining 20-30% as a buffer that absorbs burst demand, and fill true idle gaps with best-effort/preemptible jobs.', 'M/M/1 queueing at 95% utilization: mean wait = service_time / (1 - 0.95) = 20× service_time. A 2-hour training job waits ~40 hours in queue. At 80% utilization: wait = 5× = 10 hours. At 70%: wait = 3.3× = 6.6 hours. Reducing utilization from 95% to 80% cuts average wait from 40hr to 10hr (4x improvement) while losing only 15% capacity. Engineer cost: $150/hr × 30hr saved = $4,500/experiment. GPU cost of 15% idle: 1000 GPUs × 15% × $2/hr × 24hr = $7,200/day. Break-even: ~1.6 experiments saved per day.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2215.yaml', '033a8b3efab9064d0e9c4f47338f6170fb37b959b1973c7773ce45d966678b85', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2357', 'Root Causing NVSwitch MoE Contention', 'data-parallelism', 'cloud', 'L5', 'diagnosis', 'parallelism', 'evaluate', 'training', 'published', 'On a single 8x H100 node with a 900 GB/s bidirectional NVSwitch, an MoE model with 8 experts processes a batch. The intra-node All-to-All dispatch phase takes 8ms instead of the theoretical 1.1ms. `nvidia-smi nvlink` shows GPU 0 hitting 100% Rx utilization, while GPUs 1-7 show only 15% Tx utilization.', 'Why does intra-node MoE All-to-All take 8ms with GPU 0 at 100% Rx and GPUs 1-7 at 15% Tx, and how would you fix the imbalance?', 'Assuming the NVSwitch is faulty or thermally throttling, or that NCCL is misusing PCIe instead of NVLink.', 'The root cause is severe load imbalance in expert assignment, leading to NVSwitch port contention. In this MoE configuration, the gating network routes an overwhelmingly large percentage of the batch''s tokens to the expert residing on GPU 0. While the NVSwitch has massive aggregate bandwidth, each individual GPU is limited to its physical ingress link (450 GB/s unidirectional for H100). GPUs 1-7 are all trying to send data to GPU 0 simultaneously, bottlenecking on GPU 0''s Rx port. The solution is to implement an auxiliary load-balancing loss function in the model training to penalize unbalanced expert assignment, or enforce strict expert capacity limits (token dropping) to guarantee uniform traffic distribution.', 'Total batch size = 4GB (0.5GB per GPU). If perfectly balanced, GPU 0 receives 1/8th from 7 GPUs = ~0.43GB. Time = 0.43GB / 450 GB/s = 0.95ms. If highly unbalanced (e.g., 85% of tokens go to GPU 0), GPU 0 receives 3.4GB. Time = 3.4GB / 450 GB/s = 7.5ms. This perfectly matches the observed ~8ms latency.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2357.yaml', '035272ca2b24638d00500fb3f797d56020d1658db925ba34e4b03c978e4f4254', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2712', 'All-to-All Communication Volume in Expert Parallelism', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'An MoE model has 64 experts across 64 GPUs (1 expert/GPU). Each batch has 4096 tokens, each token is 2KB (FP16 hidden dim 1024). Top-2 routing means each token goes to 2 experts. Estimate the all-to-all communication volume per step.', 'For 64 experts on 64 GPUs with 4096 2KB tokens and top-2 routing, what is the all-to-all communication volume per step?', 'Only counting one direction. All-to-all requires both dispatching tokens to experts AND returning results, doubling the volume.', 'Each token (2KB) is routed to 2 experts, generating 4096 × 2 = 8192 token-expert assignments. With uniform routing, each GPU sends ~8192/64 = 128 token activations to other GPUs and receives ~128 back. Dispatch volume per GPU: 128 × 2KB = 256KB sent. Total dispatch across all GPUs: 64 × 256KB = 16MB. The combine phase (returning results) is the same volume: 16MB. Total all-to-all per step: ~32MB. This is modest compared to AllReduce on dense models, which is why MoE can scale efficiently — the communication is proportional to activated parameters (2/64 = 3%), not total parameters.', '8192 assignments × 2KB = 16MB dispatch + 16MB combine = 32MB total all-to-all. Compare to AllReduce on equivalent dense model: 64 × 1B × 2 bytes = 128GB.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2712.yaml', '60b9fe2ee9c21df94cd763b3363e815cf70af18ff517ac25533cbec6caee61f8', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3059', 'Pipeline Parallelism Optimization: Load Balancing Stages', 'pipeline-parallelism', 'cloud', 'L5', 'optimization', 'parallelism', 'evaluate', 'training', 'published', 'A 96-layer transformer is split into 4 pipeline stages on H100 GPUs (80GB HBM3). Profiling shows stage 1 takes 45ms per micro-batch, stages 2-3 take 38ms each, and stage 4 (with the language model head: vocab size 128K) takes 62ms. The pipeline throughput is bounded by stage 4. Quantify the throughput loss and propose a fix.', 'What is the correct dense FP16 TFLOPS specification for an H100 SXM5, and why is 1979 TFLOPS the wrong value to use?', 'Simply moving layers between stages without accounting for the LM head''s unique compute profile (large embedding matmul scales with vocab size, not layer count).', 'H100 FP16 TFLOPS is 989 (not 1979). 989 TFLOPS is the correct specification for H100 SXM5 dense FP16 performance.', 'H100 SXM5: 989 TFLOPS FP16 (not 1979 TFLOPS). At 40% MFU: 395.6 TFLOPS effective. 70B model decode: 140GB / 3.35 TB/s = 41.8ms/token memory-bound. Prefill 2K tokens: 2×2048×70B / 989T = 290ms. Batch=8 decode: amortized weight load = 41.8ms (same weights) → 8 tokens in 41.8ms = 5.2ms/token.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3059.yaml', '489789da14ad8e7e35b23318574c2e418b9788e3300901e0db0914008f656e6e', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3418', 'Optimizing Large Language Model Inference with Tensor Parallelism on Google TPU v5e', 'model-tensor-parallelism', 'cloud', 'L4', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'Imagine deploying a massive 175-billion parameter large language model (LLM) for real-time inference on a cluster of Google TPU v5e devices. Each TPU v5e offers 16 GB HBM, 197 TFLOPS BF16 performance, and 1.6 TB/s memory bandwidth. To fit the model and achieve low latency, you decide to use tensor parallelism. Specifically, you''re considering splitting the large linear layers (e.g., in attention mechanisms or feed-forward networks) across multiple TPU v5e chips using column-wise and row-wise partitioning. Describe the challenges and opportunities for communication-computation overlap in this setup. How would you design the tensor parallelism strategy to maximize throughput and minimize latency, considering the TPU''s architecture and interconnection?', 'How would you design TPU v5e tensor parallelism for a 175B LLM to overlap communication and computation and reduce latency?', 'A common mistake is underestimating the communication overhead, especially for all-reduce operations required when switching between column-wise and row-wise parallelism (e.g., after matrix multiplication or element-wise operations). If communication is not effectively overlapped with computation, TPUs can spend significant time idle waiting for data, leading to suboptimal utilization and higher inference latency.', 'Implement a hybrid tensor parallelism strategy where appropriate layers use column-wise partitioning (e.g., input to attention weights, feed-forward up-projection) and others use row-wise (e.g., attention output weights, feed-forward down-projection). Key to efficiency is strategically overlapping the all-reduce communication with subsequent computations. For example, during a column-wise partitioned matrix multiplication, the all-reduce for the output (needed for the next row-wise partitioned layer) can be initiated as soon as partial results are available, running concurrently with the remaining local computation for the current layer or with other independent operations. Leverage the high-bandwidth inter-chip interconnect of the TPU v5e to minimize communication latency.', 'Consider a large linear layer where the output dimension `H_out` is `12288` and the effective batch size `B*S` is `1024`. If BF16 precision is used, an all-reduce operation across `N` TPUs for the activations would involve transferring `1024 * 12288 * 2 bytes = 25.16 MB`. With the Google TPU v5e''s HBM bandwidth of 1.6 TB/s, the theoretical communication time for this data transfer would be approximately `25.16 MB / (1.6 TB/s) ≈ 15.7 microseconds`. Meanwhile, a single TPU (out of N=8) computing a matrix multiplication of `[1024, H_in] @ [H_in, H_out/8]` (assuming `H_in = H_out = 12288`) performs `1024 * 12288 * (12288/8)` BF16 operations. This amounts to approximately `19.33 billion` operations. Given the TPU v5e''s 197 TFLOPS BF16 performance, the computation time for this local part would be `19.33 * 10^9 ops / (197 * 10^12 ops/s) ≈ 98 microseconds`. Since the computation time (98 µs) is significantly larger than the communication time (15.7 µs), there is ample opportunity to effectively overlap communication with computation, maximizing TPU utilization.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3418.yaml', '0415fbdbd1b9828110e411d8f5ed4056c49d0fc856fec4ef5b3b6fa22709574b', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3422', 'Scaling a 1.5 Trillion Parameter Model on NVIDIA H100: Model and Tensor Parallelism Design', 'model-tensor-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'analyze', 'training', 'published', 'A research team is developing an extremely large language model with 1.5 trillion parameters, requiring approximately 6 TB of memory (FP16) just for its weights and activations. Your task is to design an efficient training strategy for this model on a cluster utilizing NVIDIA H100 GPUs. Each H100 provides 80 GB HBM3, 989 TFLOPS FP16 dense compute, and 3.35 TB/s memory bandwidth, connected by high-speed NVLink and InfiniBand. Propose a detailed model and/or tensor parallelism scheme. Explain how you would partition the model''s layers (e.g., across attention heads, within feed-forward networks, or layer-wise) to minimize communication overhead and maximize the effective use of H100''s capabilities. Specifically, outline how you would manage communication-computation overlap for optimal throughput. Provide napkin math to justify your partitioning strategy, focusing on memory distribution per GPU and the communication bandwidth required between GPUs for a key operation (e.g., an all-reduce within a transformer block) across a hypothetical 128-GPU setup.', 'How would you partition a 1.5T-parameter model across 128 H100s and overlap tensor/model-parallel communication with compute?', 'Overlooking the significant overhead of communication for collective operations (like all-reduce) in tensor parallelism, especially when not properly overlapping with computation. Another common mistake is not fully leveraging the HBM3 bandwidth or NVLink interconnects, leading to memory-bound or communication-bound bottlenecks despite high FLOPS. Candidates might also propose simple layer-wise parallelism without considering the activation recomputation costs or the complexity of managing variable layer sizes across devices, or failing to differentiate between memory required for weights, activations, and optimizer states.', 'A robust solution would likely combine ZeRO-stage 3 for sharding optimizer states and gradients (as the total memory exceeds HBM capacity on a single device even for weights) with a sophisticated tensor parallelism scheme (e.g., Megatron-LM or T5-style) applied to large linear layers (column-wise and row-wise partitioning). The design should emphasize: 1. Partitioning: Split large weight matrices (e.g., in FFN or attention projection layers) into column-wise or row-wise chunks, ensuring minimal data movement during forward/backward passes. 2. Communication Overlap: Aggressively overlap communication (e.g., all-reduce for gradients, all-gather for activations/weights) with computation using asynchronous operations and carefully orchestrated execution schedules. 3. Memory Optimization: Utilize activation checkpointing, CPU offloading for less critical data, and ensure efficient FP16/BF16 usage. 4. Hardware Awareness: Explicitly leverage NVLink for intra-node communication and InfiniBand for inter-node, optimizing data transfer sizes and patterns for the specific interconnect bandwidths. For instance, a column-wise split of a large linear layer would require an all-reduce operation after the matrix multiplication in the forward pass (or before in the backward pass) for activations, while a row-wise split would require an all-gather for weights or activations. The choice depends on minimizing communication volume and frequency.', 'Consider a single transformer block''s feed-forward network (FFN) with an input dimension `d_model = 16384` and an intermediate dimension `d_ff = 65536`. For an FP16 model, the `d_ff x d_model` weight matrix (or vice versa) is substantial. If we apply column-wise tensor parallelism across `P=128` GPUs for this FFN layer. The output activation (of size `batch_size * sequence_length * d_ff`) would require an all-reduce operation. Let `batch_size=1` and `sequence_length=4096`. The data size for the all-reduce for this FFN layer output: `1 * 4096 * 65536 * 2 bytes ≈ 0.5 GB`. Using a ring all-reduce model for `P=128` GPUs, the total data transferred would be approximately `2 * 0.5 GB = 1 GB`. With H100''s NVLink providing up to 900 GB/s intra-node bandwidth (for 8-GPU systems, assuming scaling or aggregation for 128 GPUs with InfiniBand for inter-node), this operation could theoretically take roughly `1 GB / 900 GB/s ≈ 1.1 ms` within an NVLink-connected node. For memory sizing, a 1.5 trillion parameter model in FP16 stores `1.5 * 10^12 * 2 bytes = 3 TB` for weights. Including activations and optimizer states, this could easily reach the stated 6TB. Distributed across 128 H100 GPUs, each GPU would ideally hold `6000 GB / 128 ≈ 46.8 GB` of the model''s total state, which comfortably fits within the 80 GB HBM3 per H100, leaving ample room for runtime activations and other overhead.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3422.yaml', '13043ad1cd2cb8ed6b830a0974f062a311be8b7faba2a254134d570ae3b850fd', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3430', 'Optimizing Large Language Model Pipeline Parallelism on AMD MI300X', 'pipeline-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'analyze', 'training', 'published', 'You are tasked with deploying an extremely large language model (LLM) with 500 billion FP16 parameters for real-time inference in a cloud environment. The chosen hardware platform is a cluster of AMD MI300X accelerators. Each MI300X features 192 GB HBM3, delivers 1,307 TFLOPS FP16 sparse performance, and boasts 5.3 TB/s memory bandwidth. Due to the LLM''s immense size, it must be distributed across multiple MI300X devices using pipeline parallelism.

Your current baseline implementation uses a naive pipeline setup with a micro-batch size of 1. This configuration results in substantial pipeline bubble overhead, leading to unacceptably high end-to-end inference latency and low device utilization.

Design an optimized pipeline parallelism strategy for this LLM on the AMD MI300X cluster. Detail how you would effectively mitigate bubble overhead, improve overall throughput, and reduce inference latency. Your design should specifically leverage the hardware capabilities (192 GB HBM3 capacity, 1,307 TFLOPS FP16 sparse, 5.3 TB/s memory bandwidth) of the MI300X. Propose an interleaved schedule for the pipeline and discuss the critical trade-offs involved in selecting an optimal micro-batch size and intelligently partitioning the model stages across the available devices.', 'How would you optimize pipeline parallel inference for a 500B FP16 LLM on MI300X to reduce bubbles, improve throughput, and lower latency?', 'A common mistake is assuming that a micro-batch size of 1 is optimal for inference latency or failing to recognize how it severely exacerbates pipeline bubble overhead. Additionally, not carefully considering the activation memory footprint vs. recomputation cost for intermediate tensors across pipeline stages can lead to OOM errors or unnecessary recomputations, negating potential gains.', 'A realistic solution involves implementing an interleaved pipeline schedule (e.g., a variant of GPipe or PipeDream) with a carefully selected micro-batch size greater than 1. The micro-batch size should be optimized to balance latency requirements with pipeline efficiency, ideally being significantly larger than the number of pipeline stages. The model should be partitioned across MI300X devices such that both computational load and memory transfer requirements (especially for intermediate activations) are balanced. Leveraging the 192 GB HBM3 for large activation storage and the 5.3 TB/s bandwidth for rapid tensor communication between stages, coupled with asynchronous communication, will help hide latency and maximize throughput.', '1. Model Weights: 500 billion FP16 parameters * 2 bytes/parameter = 1 TB. Each MI300X has 192 GB HBM3, so at least ceil(1000 GB / 192 GB/device) = 6 MI300X devices are needed just for model weights.
2. Pipeline Efficiency: For P stages and micro-batch size M, the ideal efficiency is M / (M + P - 1). If P=6 and M=1, efficiency is 1/(1+6-1) = 1/6 (16.7%). If M=16, efficiency is 16/(16+6-1) = 16/21 (76%).
3. Memory Transfer Latency: Assume an intermediate activation tensor is 10 GB. Transfer time via NVLink/Infinity Fabric inter-GPU links: 10 GB / 5300 GB/s (HBM3 bandwidth as upper bound) ≈ 1.88 milliseconds. Actual inter-node transfer over Infinity Fabric or network would be slower. This needs to be compared against the compute time of a stage to ensure transfers don''t become the bottleneck. The MI300X''s 1,307 TFLOPS FP16 sparse ensures each pipeline stage has ample compute capacity.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3430.yaml', '57a54c836e1a6d47ca3f6616eef77c388af857f02d5c69a6755a08988e045440', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3436', 'NVIDIA H100 Gradient Synchronization Performance Analysis', 'gradient-synchronization', 'cloud', 'L3', 'implement', 'parallelism', 'analyze', 'training', 'published', 'You are tasked with training a large language model with FP16 precision across a distributed cluster of 8 NVIDIA H100 GPUs. Each H100 features 80 GB HBM3 memory with 3.35 TB/s bandwidth, delivering 989 TFLOPS FP16 dense performance. The model has 70 billion parameters. You are using an AllReduce algorithm for gradient synchronization. For this distributed setup, assume the effective bidirectional communication bandwidth available for gradient exchange between any two H100 GPUs is 400 GB/s.', 'How would you estimate 8-H100 AllReduce synchronization time for 70B FP16 gradients at 400 GB/s, with and without compression?', 'A common mistake is underestimating the communication overhead, especially for large models and high GPU counts, leading to poor scaling efficiency. Overlooking the distinction between on-chip HBM3 bandwidth (3.35 TB/s) and inter-GPU communication bandwidth (e.g., NVLink or network) is frequent. Another mistake is applying aggressive gradient compression without fully understanding its impact on model convergence and training stability, or its interaction with stale gradient issues in asynchronous settings.', 'A realistic solution involves accurately modeling the communication costs, particularly for the chosen AllReduce algorithm. For a ring-based AllReduce among N GPUs, the effective data volume that must traverse the critical path is approximately `2 * G`, where `G` is the total gradient size. The synchronization time can then be estimated as `T = (2 * G) / B_inter_gpu`, where `B_inter_gpu` is the effective bidirectional communication bandwidth between GPUs. When applying gradient compression, one must factor in the reduced `G` but also consider the computational overhead for compression/decompression, its potential impact on training stability and final model quality, and the handling of stale gradients if asynchronous SGD is used. This often requires careful hyperparameter tuning and potentially adaptive compression strategies.', '1. **Total Gradient Size (G):** 70 billion parameters * 2 bytes/parameter (FP16) = 140 GB.
2. **Effective Data Transfer for AllReduce:** For a ring AllReduce across `N` GPUs, the effective data that must traverse the bottleneck link is `2 * G = 2 * 140 GB = 280 GB`.
3. **Synchronization Time (No Compression):** Time = `Effective Data / Inter-GPU Bandwidth = 280 GB / 400 GB/s = 0.7 seconds`.
4. **Synchronization Time (50% Compression):** With 50% compression, the new `G` becomes `140 GB * 0.5 = 70 GB`. New effective data = `2 * 70 GB = 140 GB`. New Time = `140 GB / 400 GB/s = 0.35 seconds`.
5. **Trade-offs for Compression:** While synchronization time is halved, consider:
   - **Convergence Impact:** Potential for slower convergence or reduced final model accuracy due to information loss from compression.
   - **Computational Overhead:** Compression/decompression adds computational load on the H100 GPUs (with 700W TDP), potentially limiting available power for core computation or increasing latency if these operations cannot be fully overlapped with compute.
   - **Stale Gradients:** Compression might interact with asynchronous SGD, potentially exacerbating issues with stale gradients if not carefully managed, as smaller gradients might lead to faster but potentially less accurate updates.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3436.yaml', '5d393e152e26c3da5ece79a6691231f375c01eef98eb9ad41528b4a81c98a01d', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3438', 'Optimizing AllReduce for Massive Models on NVIDIA A100s', 'gradient-synchronization', 'cloud', 'L3', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'You are scaling the training of a colossal language model with 200 billion FP16 parameters across 8 NVIDIA A100 GPUs (80 GB HBM2e, 312 TFLOPS FP16, 2.0 TB/s memory bandwidth) within a single server. During profiling, you observe that the AllReduce operation for gradient synchronization consumes a disproportionate amount of time in each training step, becoming a significant bottleneck even with high-bandwidth NVLink interconnects providing an effective aggregate bandwidth of 1.2 TB/s for AllReduce communication. How would you diagnose and mitigate this communication bottleneck to improve training throughput?', 'How would you diagnose and mitigate this communication bottleneck to improve training throughput?', 'Underestimating the absolute data volume of gradients for very large models and assuming the high HBM2e bandwidth (2.0 TB/s) directly translates to high inter-GPU communication bandwidth, or failing to account for AllReduce communication patterns that necessitate multiple data transfers per gradient.', 'Implement gradient compression techniques like Top-K sparsification or mixed-precision quantization (e.g., FP8/INT8) to drastically reduce the data payload for AllReduce. Explore hybrid synchronization strategies, potentially integrating asynchronous SGD or selective gradient updates if the model can tolerate a degree of staleness without compromising convergence. Tune NCCL parameters and consider network topology optimizations (e.g., hierarchical AllReduce across multiple nodes if scaling further) to maximize effective bandwidth utilization.', 'For 200 billion FP16 parameters, the total gradient size is 400 GB. With an effective aggregate NVLink bandwidth of 1.2 TB/s (1200 GB/s) for AllReduce across 8 A100s, a naive AllReduce operation would take approximately 400 GB / 1200 GB/s = 0.33 seconds per iteration. If the desired iteration time is 0.5 seconds, this leaves only 0.17 seconds for computation and other overhead, clearly indicating that gradient synchronization is the primary bottleneck and needs significant optimization.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3438.yaml', 'b3ec6573a05d2a41443ec06cb974f324887ae3b4b8a33e934e89892242dc613f', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3440', 'Optimizing Distributed LLM Training on AMD MI300X with Gradient Synchronization', 'gradient-synchronization', 'cloud', 'L4', 'optimization', 'parallelism', 'analyze', 'training', 'published', 'You are tasked with optimizing the training of a large language model (LLM) distributed across a cluster of AMD MI300X accelerators. Each MI300X boasts 192 GB of HBM3 memory, 1,307 TFLOPS of FP16 sparse compute (at peak), and a memory bandwidth of 5.3 TB/s. Despite using a highly optimized PyTorch distributed data parallel (DDP) setup, you observe that scaling efficiency significantly drops beyond 16 GPUs, with gradient synchronization becoming the dominant bottleneck, accounting for over 40% of the epoch time. The model''s training throughput is currently 250 TFLOPS/GPU, and the target is 800 TFLOPS/GPU. Diagnose the core issues and propose a strategy to achieve the target throughput.', 'How would you diagnose the >40% gradient synchronization bottleneck beyond 16 MI300X GPUs and raise throughput from 250 to 800 TFLOPS/GPU?', 'Blindly increasing batch size or using standard synchronous AllReduce without considering the communication-to-computation ratio or the specific characteristics of the MI300X''s interconnect and network topology. Another common mistake is not quantifying the communication overhead before attempting solutions.', 'Diagnose the communication pattern to identify if it''s bandwidth or latency bound. For bandwidth-bound scenarios, explore gradient compression techniques (e.g., top-k sparse gradients, FP16/int8 quantization) to reduce the data volume transferred. Evaluate various AllReduce algorithms (e.g., ring-allreduce vs. tree-allreduce based on network topology) and assess their suitability for the MI300X''s interconnect. For latency-bound scenarios or to overlap communication, investigate gradient accumulation, and potentially introduce a limited form of asynchronous SGD with careful stale gradient handling mechanisms (e.g., bounded staleness, adaptively dropping stale updates based on a scheduler) to minimize impact on convergence while maximizing compute utilization. Quantify the potential reduction in synchronization time and its impact on overall throughput.', 'Consider a large language model with 100 billion parameters. If each parameter is represented by a 32-bit float, the total gradient size is approximately 400 GB. Even with the MI300X''s impressive 5.3 TB/s HBM3 bandwidth, the challenge lies in inter-GPU communication. If the effective network bandwidth available for gradient synchronization between two nodes is 200 GB/s (a common bottleneck in multi-node training), a single full gradient AllReduce operation for 400 GB would take 400 GB / 200 GB/s = 2 seconds. If a training step takes, for example, 3 seconds of computation, spending 2 seconds on communication means only ~33% efficiency (1s compute / (1s compute + 2s comm)). If gradient compression techniques can reduce the gradient size by 8x (e.g., using FP8 or Top-K sparsity), the communication time would drop to 0.25 seconds per step, significantly improving efficiency to ~80% (1s compute / (1s compute + 0.25s comm)). The candidate should quantify the communication overhead by estimating the effective network bandwidth and the gradient data volume per step relative to the available MI300X compute.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3440.yaml', 'a2ab7f9a9a365136b086c36e0b88a20e523c9b3907c79390cbcb121c7d9ad618', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3441', 'Optimizing Distributed LLM Training via Gradient Synchronization on NVIDIA A100 Clusters', 'gradient-synchronization', 'cloud', 'L6+', 'mastery', 'parallelism', 'analyze', 'training', 'published', 'You are leading the systems design for training a 70-billion parameter large language model (LLM) across a cluster of NVIDIA A100 GPUs. Each A100 features 80 GB HBM2e memory, 312 TFLOPS FP16 performance, 2.0 TB/s memory bandwidth, and 400W TDP. Your current synchronous distributed training setup is heavily bottlenecked by gradient synchronization. Design a comprehensive gradient synchronization strategy that addresses these bottlenecks. Consider the trade-offs and applicability of different AllReduce algorithms (e.g., Ring AllReduce, Tree AllReduce), gradient compression techniques (e.g., Top-K, 1-bit SGD), and the potential for asynchronous SGD. If you opt for asynchronous SGD, detail your strategy for handling stale gradients to maintain model convergence. Justify your choices by referencing the NVIDIA A100''s specifications and quantify the expected performance improvements or necessary compromises.', 'How would you design gradient synchronization for a 70B-parameter LLM on A100s using AllReduce, compression, or async SGD while controlling stale gradients?', 'A common mistake is a ''one-size-fits-all'' approach to gradient synchronization, either blindly using full-precision AllReduce or overly aggressive compression. This often neglects the specific communication topology, network bandwidth, GPU memory constraints, and the sensitivity of the model to gradient noise. Forgetting to overlap communication with computation or overlooking the impact of data transfer via PCIe vs. NVLink also leads to suboptimal performance.', 'A realistic solution would involve a hybrid approach. For smaller models or low-latency networks (like NVLink within a node), an optimized synchronous AllReduce (e.g., NCCL''s Ring AllReduce) with FP16 gradients would be the baseline, leveraging the A100''s high memory bandwidth (2.0 TB/s) for rapid local gradient accumulation and fast inter-GPU communication. For larger models or inter-node communication over slower networks (e.g., InfiniBand), gradient compression like Top-K (with dynamic K based on training phase) or a combination of quantization and sparsification would be critical to reduce communication volume. Asynchronous SGD could be considered for specific non-critical model components or during phases less sensitive to staleness, implemented with a parameter server or decentralized peer-to-peer updates, coupled with a bounded staleness policy (e.g., ''Averaged SGD'' or waiting for a minimum number of updates from faster workers). The system should pipeline communication and computation using CUDA streams to maximize A100''s compute (312 TFLOPS FP16) utilization.', 'Consider a 70B parameter LLM, trained with FP16 precision (2 bytes/parameter). Total gradient size = 70B * 2 bytes = 140 GB. For an 8-GPU A100 node with NVLink (~600 GB/s aggregate bidirectional bandwidth per GPU, but effective AllReduce bandwidth is lower, say 200 GB/s for simplicity across 8 GPUs): a full AllReduce of 140 GB gradients would take approximately (2 * (N-1)/N * MessageSize) / Bandwidth ≈ (2 * (7/8) * 140 GB) / 200 GB/s ≈ 1.225 seconds per step. If a single A100 performs computation for a small batch in 0.5 seconds, this becomes a severe bottleneck. With 95% Top-K gradient compression, the message size reduces to 7 GB. Communication time then becomes ≈ (2 * (7/8) * 7 GB) / 200 GB/s ≈ 0.061 seconds, making it much less of a bottleneck and potentially allowing for overlap.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3441.yaml', '9e136670cca96825de62d464e277fae4296ab1edb82faceeeb5ee0d110df7923', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3444', 'Designing a Multi-Tenant ML Platform with AMD MI300X', 'scheduling-resource-management', 'cloud', 'L5', 'design', 'parallelism', 'analyze', 'inference', 'published', 'Your team is building a multi-tenant machine learning platform in the cloud. Each tenant requires access to high-performance GPU resources for training and inference. You have a cluster of AMD MI300X accelerators, each boasting 192 GB HBM3 memory, 1,307 TFLOPS FP16 sparse compute, and 5.3 TB/s memory bandwidth. Design a robust resource management and scheduling system that can efficiently allocate these GPUs, handle varying workload priorities, prevent resource contention, and ensure fairness across tenants. Specifically, consider how to implement fine-grained GPU partitioning (e.g., similar to NVIDIA''s MIG/MPS concepts but for AMD hardware), gang scheduling for distributed workloads, preemption for high-priority jobs, and mechanisms for multi-tenant resource isolation and sharing on this specific hardware.', 'How would you design MI300X resource management for multi-tenant ML with GPU partitioning, gang scheduling, preemption, and isolation?', 'Ignoring the specific hardware capabilities and limitations of the AMD MI300X, leading to suboptimal partitioning strategies or inefficient memory utilization. A common mistake is also not properly accounting for the overhead of context switching and memory isolation in a multi-tenant environment, especially with the high memory bandwidth, leading to performance cliffs and ''noisy neighbor'' issues.', 'A hierarchical scheduling approach would be effective. At the lowest level, implement a custom GPU partitioning mechanism leveraging AMD''s hardware features (e.g., defining virtual GPU instances or dedicated compute units within the MI300X, similar to how software/firmware could define virtual GPUs) to allow multiple tenants to share a single physical GPU with strong memory and compute isolation. Integrate this with a cluster scheduler (e.g., Kubernetes with custom device plugins or Slurm) that supports gang scheduling for distributed training jobs. Implement preemption policies based on job priority and resource utilization, ensuring graceful checkpointing/restoring for preempted jobs. Utilize cgroups-like mechanisms for resource limits and continuously monitor GPU metrics (utilization, memory consumption, HBM bandwidth) to dynamically adjust allocations and detect noisy neighbors, ensuring fair resource distribution.', 'Given an AMD MI300X with 192 GB HBM3, if two tenants require models with memory footprints of 48 GB and 96 GB respectively, and assuming we reserve 20% of the total HBM3 for system overheads, how many such tenant pairs could ideally fit on a single MI300X? Usable HBM3: 192 GB * 0.8 = 153.6 GB. Memory required per pair: 48 GB + 96 GB = 144 GB. Number of pairs: 153.6 GB / 144 GB ≈ 1.06. This indicates that accommodating even one such pair leaves very little room, emphasizing the need for dynamic, flexible partitioning or leveraging smaller model sizes for efficient multi-tenancy.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3444.yaml', '931b9a8aa7453bd4f750977dcea42d099e60bce8ecf04dfda8d7c448abb77cfe', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3448', 'Optimizing Multi-Tenant LLM Inference on NVIDIA H100 with Advanced Scheduling', 'scheduling-resource-management', 'cloud', 'L4', 'optimization', 'parallelism', 'analyze', 'inference', 'published', 'You are managing a multi-tenant ML inference service on a cluster of NVIDIA H100 GPUs (each with 80 GB HBM3, 989 TFLOPS FP16 dense for FP16, and 3.35 TB/s memory bandwidth, consuming 700W). Your team has deployed a large language model (LLM) for real-time inference, which is highly sensitive to latency. Recently, users have reported inconsistent latency, with p99 latencies spiking unexpectedly, especially during peak hours. You suspect contention for GPU resources is the primary culprit, exacerbated by varying workload patterns from different tenants. How would you diagnose the specific bottleneck (e.g., compute, memory bandwidth, interconnect) and propose a solution utilizing techniques like MIG/MPS partitioning or gang scheduling to improve p99 latency by at least 20%? Quantify the expected performance improvement or resource utilization change with your proposed solution, referencing the H100''s capabilities.', 'How would you diagnose H100 multi-tenant inference p99 spikes and use MIG, MPS, or gang scheduling to cut p99 latency by at least 20%?', 'A common mistake is to immediately scale out the cluster without properly identifying the root cause of contention. This can lead to increased operational costs without solving the core ''noisy neighbor'' problem, or to implementing naive FIFO scheduling policies that don''t account for preemption or fair resource sharing in multi-tenant environments, worsening tail latencies for critical services.', 'The most realistic solution involves a two-pronged approach: diagnosis and targeted intervention. For diagnosis, leverage `nvidia-smi` with `--query-gpu=utilization.gpu,utilization.memory,pstate,memory.used,memory.total --format=csv` to monitor overall GPU health. Utilize CUDA profiling tools like Nsight Systems and Nsight Compute to gather fine-grained per-kernel performance metrics, identifying specific kernels (e.g., attention, MLP) that are compute-bound or memory-bound. System-level monitoring (e.g., Prometheus/Grafana) should track per-tenant GPU utilization, memory bandwidth, and inference request queues. Once bottlenecks are identified, implement NVIDIA MIG (Multi-Instance GPU) to partition the H100 into dedicated 1/7 or 1/3 slices, ensuring guaranteed compute and memory resources (e.g., a 1/7 slice provides ~11.4GB HBM3 and ~478 GB/s bandwidth) for latency-sensitive LLMs. For interdependent inference requests from a single tenant, employ gang scheduling to ensure all necessary processes run concurrently, minimizing context switching overhead and ensuring fairness. For less critical workloads, utilize MPS (Multi-Process Service) for shared GPU access with better resource management than traditional CUDA multi-process execution.', 'Assume the current p99 inference latency is 500ms. The goal is to reduce it by 20%, targeting 400ms. Through profiling, you discover that 150ms of the p99 latency is due to intermittent memory bandwidth contention caused by another tenant''s data loading (bursts of 200GB/s I/O, hitting the H100''s 3.35 TB/s limit when combined with the LLM workload). Another 50ms is attributable to overheads from non-gang-scheduled, parallel inference sub-tasks within the LLM, leading to inefficient resource utilization and context switching. By configuring MIG to allocate a dedicated 1/7 H100 instance (providing ~478 GB/s guaranteed memory bandwidth) for the critical LLM tenant, the 150ms memory contention is eliminated. Implementing gang scheduling for the LLM''s parallel components reduces context switching, saving the 50ms overhead. The total potential reduction is 150ms + 50ms = 200ms. The new p99 latency would be 500ms - 200ms = 300ms. This represents a (200/500)*100% = 40% reduction, significantly exceeding the 20% target. The quantifiable fix is a 40% improvement in p99 latency by isolating critical workloads'' memory bandwidth and optimizing parallel task execution.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3448.yaml', '1e98dbf84f34820d44d4b21d25c18476fe523a9bd1bc753fa879faf86890fbf5', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3662', 'Tensor Parallelism Degree Selection for 70B Model on H100', 'model-tensor-parallelism', 'cloud', 'L4', 'design', 'parallelism', 'evaluate', 'training', 'published', 'You''re serving a 70B Llama-2 model (140GB FP16) on H100 (80GB HBM3, 3.35TB/s, NVLink 900GB/s) nodes with 8 GPUs each. You must choose tensor parallelism degree: TP=2, TP=4, or TP=8. Each degree has different communication overhead. Batch size is 1 for latency-sensitive serving.', 'Which tensor-parallelism degree—TP=2, TP=4, or TP=8—would you choose for batch-1 70B serving on an 8-H100 node, and why?', 'Choosing TP=8 to maximize memory distribution without considering that each all-reduce in TP must complete before the next layer can begin. At batch=1, the model is memory-bandwidth-bound, and TP communication overhead dominates.', 'TP=2 or TP=4 is optimal for latency at batch=1. TP=8 introduces 7 all-reduce operations per layer (one per attention + one per MLP), each requiring synchronization across 8 GPUs. With NVLink, all-reduce of 128MB takes ~0.14ms per operation * 80 layers * 2 = 22ms just in communication. TP=2 reduces communication to ~5ms. Use TP=4 for memory fit with minimal communication overhead.', '70B model = 140GB FP16. TP=2: 70GB/GPU — fits in H100 80GB with 10GB headroom. TP=4: 35GB/GPU — comfortable. TP=8: 17.5GB/GPU — wastes 62.5GB/GPU. All-reduce per layer at TP=N: 2*(N-1)/N * tensor_size / BW. Tensor size = hidden_dim * 2 bytes = 8192 * 2 = 16KB per all-reduce for residual stream. At NVLink 900GB/s: 16KB/900GB/s = 0.018μs per all-reduce. But for weight shards in MLP: 8192*32768*2 = 512MB per layer → 512MB/900GB/s = 0.57ms per all-reduce. TP=8 adds 80 layers * 2 all-reduces * 0.57ms = 91ms communication overhead per token.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3662.yaml', 'bfbe2328a7ac56dffabc518eacdb2f989651254a3fccc1a43ee9c0b8e981af46', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3934', 'Gradient Compression to Improve Overlap Feasibility at Scale', 'communication-computation-overlap', 'cloud', 'L5', 'optimization', 'parallelism', 'apply', 'both', 'published', 'Your 175B model trained across 512 A100 GPUs has AllReduce time (104ms) that exceeds backward pass time (80ms). Even with perfect overlap, 24ms of communication is exposed. Gradient compression is proposed to reduce communication volume. Evaluate the tradeoff.', 'Which gradient compression approach would you choose to hide the 104 ms AllReduce within the 80 ms backward pass, and why?', 'Applying aggressive compression (e.g., 1-bit SGD or top-k with 99% sparsity) without accounting for convergence slowdown. The training time saved per step can be lost to needing more steps to converge.', 'Compression options: (1) FP16 gradients instead of FP32: 2x compression, virtually no convergence impact (already standard). AllReduce: 52ms -> fits in 80ms backward. (2) PowerSGD (rank-4 approximation): ~10x compression with <1% convergence impact for most models. AllReduce: ~10ms, easily hidden. (3) Top-k (1% sparsity): 100x compression but requires error feedback and typically needs 1.2-1.5x more steps to converge. (4) FP8 gradients (H100-specific): 4x compression, emerging technique with mixed convergence results. Recommendation: PowerSGD is the sweet spot — enough compression to make overlap feasible while maintaining convergence quality.', 'AllReduce for 175B x 4 bytes = 700GB at 50 GB/s = 14 seconds (non-overlapped). With PowerSGD 10x: 70GB / 50 = 1.4 seconds, now fits within 80ms backward per bucket. Convergence overhead: ~5% more steps. Net speedup: (14s - 1.4s) / 14s = 90% communication reduction, minus 5% convergence = 85% net improvement.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3934.yaml', 'b08a0b5a011b67674a9510b172ee79a44e819fd03fe454b005656a2867b201e5', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3935', 'Interleaved Pipeline Schedules: Zero-Bubble Pipeline Parallelism', 'communication-computation-overlap', 'cloud', 'L6+', 'mastery', 'parallelism', 'evaluate', 'both', 'published', 'The Megatron-LM team introduced interleaved pipeline scheduling where each device holds multiple non-contiguous pipeline stages. For a 32-layer model with 4 pipeline stages, each device handles 8 layers in an interleaved pattern (device 0: layers 0,4,8,...28). Evaluate how this reduces the pipeline bubble compared to 1F1B.', 'How much does interleaved pipeline scheduling reduce the 1F1B bubble for a 32-layer model with 4 stages, and what is the tradeoff?', 'Assuming interleaved scheduling is strictly better than 1F1B. While it reduces the bubble, it increases point-to-point communication because non-contiguous stages require more cross-device tensor transfers.', 'Interleaved scheduling with virtual pipeline stages (v): each device holds v chunks of layers. With k=4 physical stages and v=2 virtual stages per device: effective pipeline depth = k*v = 8 virtual stages, each processing 4 layers. Bubble fraction = (k-1)/(m*v + k-1). For m=8 micro-batches: standard 1F1B = 3/11 = 27.3%, interleaved (v=2) = 3/19 = 15.8%, interleaved (v=4) = 3/35 = 8.6%. However, communication increases by v-fold: with v=2, each micro-batch traverses the network 2x. On NVLink (low latency), this is acceptable. On InfiniBand (higher latency), the extra communication may negate bubble savings. Profile both configs to find the optimal v for your network topology.', '32-layer 70B model. 1F1B bubble: 27.3% x 2200ms = 600ms wasted. Interleaved v=2: 15.8% x 2200ms = 347ms wasted, but extra comms: 8 micro-batches x 4 extra sends x 5ms = 160ms. Net: 347 + 160 = 507ms vs 600ms. Marginal win. At v=4: 8.6% x 2200ms = 189ms + 320ms comms = 509ms. Diminishing returns.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3935.yaml', '39fa8a93de04f9e6c3f062cf6a24950d7a434a19e59da4e7787de3f0c1cec8f6', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3962', 'Overlap-Aware Job Scheduling on Shared GPU Clusters', 'communication-computation-overlap', 'cloud', 'L6+', 'evaluation', 'parallelism', 'evaluate', 'both', 'published', 'Your GPU cluster runs multiple DDP training jobs. Job A (8 GPUs, 200ms backward, 100ms AllReduce) and Job B (8 GPUs, 50ms backward, 100ms AllReduce) share the same InfiniBand fabric. When both run simultaneously, Job A''s AllReduce time jumps to 180ms because of fabric contention. Job A''s overlap breaks. Evaluate cluster scheduling policies to protect overlap efficiency.', 'Which cluster scheduling policies would protect Job A''s overlap when Job B causes InfiniBand contention?', 'Scheduling jobs purely based on GPU availability without considering network topology. Two communication-heavy jobs sharing the same IB switches destroy each other''s overlap efficiency.', 'Network-aware scheduling: (1) Topology-aware placement: assign jobs to GPU groups that share dedicated IB switches (locality). Job A on switches 1-2, Job B on switches 3-4. No contention. (2) Time-division multiplexing: schedule communication-heavy jobs to stagger their AllReduce phases. If Job A''s AllReduce is at t=200ms and Job B''s at t=50ms, they naturally stagger. (3) Network isolation: use IB partitioning (PKeys) to guarantee bandwidth per job. (4) Priority-based QoS: mark Job A''s NCCL traffic as high-priority in IB''s SL-to-VL mapping. (5) Evaluation: topology-aware placement is simplest and most effective — it eliminates contention with zero runtime overhead. Modern schedulers (Slurm + topology plugin, Kubernetes + network topology awareness) support this.', 'Job A with contention: 200ms backward + 80ms exposed AllReduce (180ms - 100ms overlap capacity) = 280ms/step. Without contention: max(200, 100) = 200ms/step. Contention cost: 80ms/step = 40% throughput loss. For a 24-hour job: 9.6 hours wasted on network contention.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3962.yaml', '34f1e88b0c7d3c8390a28dea1b0d2674a3b58bd1426d53243387b2061e90ba14', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0687', 'The Optimizer Explosion', '3d-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are training a 30B parameter model. You calculate that the weights only take up 60 GB, which fits easily into an 80 GB H100. However, the system OOMs (Out-of-Memory) instantly on the first step. Based on the diagram, what is the hidden memory tax you missed?', 'Based on the diagram, what is the hidden memory tax you missed?', '"60 GB fits in 80 GB, so the batch size must be too large." Batch size matters, but even with batch size 1, this system OOMs — the hidden cost is the optimizer, not the data.', 'The system OOMs because of the **Optimizer State**. Adam stores two additional tensors per parameter (first and second moments), plus master weights, all in FP32. ZeRO (Zero Redundancy Optimizer) or FSDP is the fix. Instead of replicating the full optimizer state on every GPU, shard it across all workers. ZeRO Stage 3 shards weights, gradients, and optimizer states, reducing per-GPU memory from 480 GB to ~120 GB across 4 GPUs.', 'A 30B parameter model''s FP16 weights require 30B * 2 bytes = 60GB, seemingly fitting an 80GB H100. However, training requires gradients (FP16, 60GB) and Adam optimizer states: FP32 master weights (120GB), FP32 momentum (120GB), and FP32 variance (120GB). Total memory needed = 60 + 60 + 120 + 120 + 120 = 480GB per GPU! The hidden Adam memory tax causes an instant OOM.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0687.yaml', '99532e5bbb4a5c3023244d176a0fe825c885207015f9015bb3a876344a85dca2', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0823', 'The Gradient AllReduce Time', '3d-parallelism', 'cloud', 'L1', 'recall', 'parallelism', 'remember', 'training', 'published', 'You are running data-parallel training of a 7B model across 8 H100 GPUs in a single node connected via NVLink 4.0 (900 GB/s bidirectional). Gradients are in FP32. How long does the AllReduce synchronization take?', 'How long does the AllReduce synchronization take?', 'Using FP16 gradient size instead of FP32, or forgetting the 2*(N-1)/N ring AllReduce overhead factor. Some candidates also confuse bidirectional bandwidth with unidirectional.', 'About 54 ms. Gradient size = 7B * 4 bytes = 28 GB. Ring AllReduce sends 2*(N-1)/N * data volume = 2*(7/8)*28 = 49 GB over the ring. At 900 GB/s NVLink: 49/900 ~ 54 ms.', 'Gradients = 7B * 4 bytes (FP32) = 28 GB. Ring AllReduce factor = 2*(8-1)/8 = 1.75. Total traffic = 1.75 * 28 = 49 GB. Time = 49 GB / 900 GB/s ≈ 0.054 s ≈ 54 ms.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0823.yaml', '8ef35292681def8ec2bda7b5d200c1c28a7ea48cac3d4ab48079398568f81769', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0899', 'Evaluating Parallelism Mapping Across the Bandwidth Taper', 'data-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'Your team is architecting the distributed training topology for a 175B parameter LLM on a cluster of NVIDIA H100 nodes (8 GPUs per node). The hardware features a severe bandwidth taper: 900 GB/s intra-node via NVLink, and 50 GB/s (400 Gbps) inter-node via InfiniBand. A junior engineer proposes spanning Tensor Parallelism (TP) across multiple nodes to maximize memory pooling, while keeping Pipeline Parallelism (PP) contained within individual nodes to reduce pipeline bubbles. Evaluate this proposal and justify a mathematically sound topology.', 'Should tensor parallelism span multiple H100 nodes here, or how should TP, PP, and DP be mapped across the cluster?', 'Failing to quantify the communication intensity of TP versus PP, and ignoring the 18x bandwidth taper, leading to a topology where the highest-volume, blocking communications are forced over the slowest interconnect.', 'Reject the proposal. TP requires blocking All-Reduce operations for every layer, which will bottleneck on the 50 GB/s InfiniBand. PP only communicates activations at stage boundaries. The optimal topology maps TP strictly within the node to leverage the 900 GB/s NVLink, and maps PP and Data Parallelism (DP) across nodes.', 'Bandwidth taper ratio: NVLink (900 GB/s) / InfiniBand (50 GB/s) = 18x. For a hidden dimension of 12,288, seq length 2,048, and batch size 4, a single TP All-Reduce transfers ~400MB per layer. Over InfiniBand, this takes 8ms per layer. Over NVLink, it takes ~0.44ms. Across 96 layers, inter-node TP adds ~768ms of blocking overhead per step, ruining GPU utilization.', 'imported', '2026-03-23T21:02:34.615108', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0899.yaml', 'a026554827a7cd363432b409a0146ea3153a940fbf06f37b151815f357fd3a68', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1059', 'Overlapping Data Transfers with CUDA Streams', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are deploying an inference pipeline on a T4 GPU (PCIe Gen3 x16, 12 GB/s). For each batch, the host-to-device (H2D) transfer takes 5 ms, the inference kernel takes 10 ms, and the device-to-host (D2H) transfer takes 3 ms. You need to process 100 consecutive batches. Calculate the total execution time if you process batches synchronously in the default stream versus pipelining them across 3 concurrent CUDA streams.', 'What is the total execution time for 100 batches synchronously versus pipelined across 3 CUDA streams?', 'Candidates often assume total execution time with streams is simply divided by the number of pipeline stages, ignoring that the longest pipeline stage (compute at 10 ms) strictly dictates the maximum overall throughput.', 'In synchronous mode, each batch takes 5 + 10 + 3 = 13 ms sequentially, totaling 1800 ms for 100 batches. With CUDA streams overlapping H2D, compute, and D2H, the steady-state throughput is bottlenecked by the 10 ms compute kernel. The total time is the latency of the first batch plus the bottleneck time for the remaining 99 batches: 18 ms + (99 * 10 ms) = 1008 ms.', 'Synchronous = 100 batches * (5 ms H2D + 10 ms Compute + 3 ms D2H) = 1800 ms.
Pipelined (Streams) = T_first_batch + (N-1) * max(T_stages) = (5 + 10 + 3) + 99 * 10 = 18 + 990 = 1008 ms.
Speedup = 1800 / 1008 ≈ 1.78x.', 'imported', '2026-03-23T21:38:09.294410', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1059.yaml', '833d2b7aa56fa1767fae05819975e2ed73611f77c6b33c3278fc96c698f15119', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1088', 'Diagnosing DDP Network Bottlenecks', 'data-parallelism', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'training', 'published', 'You are training a 2-billion parameter model using PyTorch Distributed Data Parallel (DDP) across 4 nodes (8x A100 80GB GPUs per node), connected via 100 Gbps Ethernet. Single-node GPU utilization is 98%, but drops to 42% when scaling to 4 nodes. Profiling shows GPUs are stalling during the backward pass synchronization. Diagnose the root cause of this sub-linear scaling and propose a software-only solution without changing the model architecture.', 'What is causing GPU utilization to drop from 98% to 42% across 4 nodes, and what software-only fix improves scaling?', 'Candidates often misdiagnose this as a CPU dataloader bottleneck or immediately suggest transitioning to Tensor Parallelism without calculating the exact communication-to-computation ratio that reveals the network as the binding constraint.', 'The root cause is the 100 Gbps inter-node network bottlenecking the AllReduce of FP16 gradients. Ring AllReduce transfers 6GB per node at 12.5 GB/s, taking 0.48s vs 0.2s compute — yielding only 29.4% GPU utilization. Implement gradient accumulation (e.g., 4 steps using PyTorch''s `no_sync()` context) to increase effective compute time to 0.8s, raising serial utilization to ~62.5%. Combined with gradient-communication overlap, effective utilization approaches 80-90%.', '2B params in FP16 = 4GB gradients. Ring AllReduce transfers 2*(N-1)/N * Size = 2*(3/4)*4GB = 6GB per node. At 100 Gbps (12.5 GB/s), communication takes 6 / 12.5 = 0.48s. If compute takes 0.2s per step, max utilization is 0.2 / (0.2 + 0.48) = 29.4%. Accumulating 4 steps increases compute time to 0.8s. Serial utilization improves to 0.8 / (0.8 + 0.48) = 62.5%. With gradient-communication overlap (using DDP''s bucketed all-reduce during backward), effective utilization can approach ~80-90%.', 'imported', '2026-03-23T21:44:55.607713', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1088.yaml', '43f6fedd916c58d44ef107bffd44f8e5e3ccd96ddd4ca462da448187e3c6bcfd', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1578', 'Diagnosing MoE Routing and OOM Bottlenecks', 'mixture-of-experts', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'both', 'published', 'You are serving an 8x7B Mixture of Experts (MoE) model (56B total parameters, 14B active per token) across an 8x A100 80GB node using Expert Parallelism (1 expert per GPU). The total model weights are ~112GB in FP16, easily fitting in the 640GB cluster memory. However, at a batch size of 256 and sequence length of 2048, you experience intermittent Out-of-Memory (OOM) crashes on specific GPUs and massive tail latency spikes. Standard metrics show average cluster GPU utilization is below 40%. Diagnose the root cause of the OOM crashes and the latency degradation.', 'Why do specific GPUs OOM and tail latency spike under expert parallelism, and how should you fix the 8x7B MoE serving path?', 'Candidates often blame the total KV cache size or general all-to-all communication overhead, missing that Expert Parallelism makes individual GPU memory and compute dependent on dynamic routing distributions. They often suggest global batch size reduction instead of addressing expert imbalance.', 'The root cause is severe load imbalance (token skew) where the router sends a disproportionate number of tokens to a single expert. This causes the target GPU to exceed its 80GB VRAM limit due to localized activation and KV cache spikes, and serializes compute, causing tail latency. The fix is to implement a strict expert capacity limit (token dropping/overflow to other experts) and combine Expert Parallelism with Tensor Parallelism to distribute the hot expert''s memory footprint.', 'Total VRAM: 8x80GB = 640GB. Model: 56B * 2B = 112GB (14GB/GPU). Remaining VRAM/GPU: 66GB. Normal per-GPU KV/activations at balanced load (1/8th of tokens): ~8GB. If routing is heavily skewed (e.g., 90% of tokens to Expert 2), GPU 2 processes ~470k tokens instead of 65k. The activation/KV memory for 470k tokens on a single GPU balloons past the 66GB remaining headroom, causing an OOM on GPU 2 while GPUs 0, 1, 3-7 sit idle with plenty of free memory.', 'imported', '2026-03-23T23:39:17.456643', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1578.yaml', 'b30dd8dc5b58e01ec3fd1f768277cfa405e0976c16591ab50a88b291681d4a1d', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1609', 'Calculating Minimum Model Parallelism Degree', 'model-tensor-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are provisioning a training cluster for a 30-billion parameter transformer model using standard mixed-precision training (FP16 with Adam optimizer). Without using ZeRO-style optimizer state partitioning, the model states (weights, gradients, FP32 master weights, momentum, variance) must be distributed across devices using pure Model Parallelism. The cluster uses NVIDIA A100 GPUs with 40GB of HBM each. Assume you need to reserve 8GB per GPU strictly for activations and workspace. Calculate the minimum required degree of Model Parallelism to fit the training state.', 'What minimum model-parallelism degree is needed to fit the 30B mixed-precision Adam training state on 40GB A100s?', 'Calculating memory requirements based only on the 16-bit model weights (which would be 60GB total, incorrectly implying just 2 GPUs), completely ignoring the 14 bytes/param overhead of gradients, master weights, and Adam optimizer states.', 'In standard mixed-precision training, each parameter requires 16 bytes of memory (2 bytes for FP16 weights, 2 bytes for FP16 gradients, 4 bytes for FP32 master weights, 4 bytes for FP32 momentum, and 4 bytes for FP32 variance). A 30B parameter model thus requires 480GB of memory. With 32GB of usable memory per 40GB GPU, 15 GPUs are mathematically required. To maintain symmetrical division across attention heads and efficient communication topologies, the realistic minimum Model Parallelism degree is 16.', 'State per param = 2 (FP16 W) + 2 (FP16 G) + 4 (FP32 W) + 4 (FP32 M) + 4 (FP32 V) = 16 bytes.
Total Model State = 30e9 * 16 bytes = 480 GB.
Usable GPU Memory = 40 GB - 8 GB (activations) = 32 GB.
Minimum GPUs = 480 GB / 32 GB = 15 GPUs.
Nearest hardware-friendly power of 2 = 16.', 'imported', '2026-03-23T23:48:10.749702', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1609.yaml', '3019340c3902abf05c3522d34dadc5bb819695645933253197e7a80ca80dea9f', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1748', 'Process Group Misalignment in 3D Parallelism', 'data-parallelism', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'training', 'published', 'You are debugging a 175B parameter model training job on a 1024-GPU A100 cluster (128 nodes, 8 GPUs/node) using 3D parallelism (TP=8, PP=16, DP=8). You observe massive latency spikes in the attention projection AllReduce operations, degrading throughput by 60%. Network profiling shows that these TP AllReduce operations, which should exclusively use the 600 GB/s NVLink intra-node bandwidth, are inexplicably generating heavy traffic on the 400 Gbps InfiniBand inter-node network. Root-cause the bottleneck.', 'Why are TP AllReduce operations spilling onto InfiniBand instead of staying on NVLink, and what process-group fix is needed?', 'Assuming `torch.distributed.all_reduce` automatically infers and routes traffic based on the tensor''s parallelism dimension without needing an explicitly defined localized process group.', 'Diagnose that the AllReduce call is missing the `group` argument and defaulting to the global process group (all 1024 GPUs). Fix it by explicitly passing the initialized Tensor Parallel process group (e.g., `group=tp_group`) to restrict NCCL communication to the 8 GPUs on the local node.', 'NVLink intra-node bandwidth = 600 GB/s. InfiniBand inter-node bandwidth = 50 GB/s (400 Gbps). A 500MB AllReduce on NVLink takes ~1.7ms. Attempting to synchronize this globally over the 50 GB/s NIC takes >20ms, introducing a 12x latency penalty per attention block and stalling the pipeline.', 'imported', '2026-03-24T00:32:28.917323', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1748.yaml', '558efe10eadda570a923a89b59861575ada816a17c1cf58c1fcdafe72ff41795', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1751', 'Calculate 3D Parallelism Process Groups', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are deploying a 175B parameter LLM on a 512 GPU cluster (A100, 8 GPUs per node) using 3D parallelism. You configure the environment with a Tensor Parallelism (TP) size of 8, Pipeline Parallelism (PP) size of 8, and Data Parallelism (DP) size of 8. Calculate the total number of specialized NCCL process groups created for TP, PP, and DP communication, and determine the number of GPUs in each group.', 'How many TP, PP, and DP NCCL process groups are created for TP=8, PP=8, DP=8 on 512 GPUs, and how large is each group?', 'Assuming there are only 3 process groups in total (one for TP, one for PP, one for DP), rather than recognizing the Cartesian grid structure where multiple orthogonal groups exist across the cluster.', 'In a 3D parallel setup, the GPUs form a DP x PP x TP grid. The number of process groups for any one dimension is the product of the sizes of the other two dimensions. Thus, there are 64 TP groups, 64 PP groups, and 64 DP groups, each containing 8 GPUs, resulting in 192 total specialized process groups.', 'Total GPUs = DP(8) × PP(8) × TP(8) = 512
TP Groups = DP × PP = 8 × 8 = 64 (Size 8)
PP Groups = DP × TP = 8 × 8 = 64 (Size 8)
DP Groups = PP × TP = 8 × 8 = 64 (Size 8)
Total groups = 64 + 64 + 64 = 192', 'imported', '2026-03-24T00:33:05.637630', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1751.yaml', '178de88aa0ee95f21f5a1081cd043ce29c8c8bb0ec6127d7a5cb5076d51adf26', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1840', 'LSTM Sequential Latency Bound on A100 GPUs', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are optimizing an LSTM-based sequence-to-sequence model for real-time translation on an NVIDIA A100 GPU. The model uses a hidden size of 2048 and processes sequences of length 512. Profiling shows that a single LSTM cell state update (dominated by a 2048x2048 matrix multiplication) takes 5 microseconds on the A100. A junior engineer suggests increasing the batch size to 256 to fully saturate the GPU''s tensor cores and drastically reduce the end-to-end latency of processing a 512-token sequence. Calculate the theoretical minimum latency for a single sequence and evaluate the engineer''s claim.', 'What is the theoretical minimum latency for one 512-token LSTM sequence, and will increasing batch size to 256 reduce it?', 'Assuming that massive parallel compute capacity or increased batch size can parallelize operations across the time dimension of an LSTM, thereby reducing end-to-end sequence latency.', 'Batching increases throughput but cannot bypass the sequential dependency constraint where the hidden state h_t relies on h_{t-1}. The minimum latency is strictly bounded by the number of time steps multiplied by the computation time of a single step.', 'Time per step = 5 µs. Sequence length (N) = 512. Minimum sequence latency = N * 5 µs = 512 * 5 µs = 2560 µs = 2.56 ms. Batching to 256 improves overall sequences/sec (throughput) but the latency for processing any individual 512-token sequence remains bounded at 2.56 ms. The engineer is incorrect.', 'imported', '2026-03-24T00:54:35.078036', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1840.yaml', '6b848c18ca49b5bc8b3ad505aaaecff2ceac9dc9e0a3f6e1dc58327feebd24ab', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2701', 'SSP vs BSP vs ASP Selection', 'data-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'A 256-GPU training job on a heterogeneous cluster shows 30% straggler variance. The model is a 7B LLM where convergence quality is critical. The team is split between BSP with backup workers, SSP with S=3, and pure ASP. Evaluate the trade-offs and recommend an approach.', 'For the 256-GPU 7B LLM with 30% straggler variance, should you use BSP with backups, SSP S=3, or pure ASP?', 'Choosing ASP for maximum throughput without considering that 7B LLM training is sensitive to gradient quality — stale gradients can waste entire training runs.', 'ASP is too risky: with 256 workers and 30% variance, the fastest workers would be dozens of steps ahead, producing severely stale gradients that can destabilize LLM convergence. BSP with backup workers is safe for convergence but wastes ~20-30% of compute on redundant work. SSP with S=3 is the best trade-off here: it allows fast workers to proceed (absorbing the 30% straggler variance most of the time) while bounding staleness to 3 steps, which empirically preserves convergence quality for LLMs. The recommendation is SSP with S=3, combined with gradient clipping to handle the mild staleness. Monitor the loss curve — if it diverges, reduce S to 2.', 'ASP: unbounded staleness across 256 workers → divergence risk. BSP+backup: ~20-30% wasted compute. SSP S=3: blocks only when gap>3, throughput ~1.4-1.6x over BSP.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2701.yaml', '56caa07f5a19b0da60c4987609545941448be8b1dd64de4587a499a31546262d', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2711', 'Expert Parallelism in MoE', 'data-parallelism', 'cloud', 'L2', 'recall', 'parallelism', 'understand', 'training', 'published', 'Explain how expert parallelism differs from standard model parallelism. Why is a specialized strategy needed for Mixture of Experts models rather than just using tensor or pipeline parallelism?', 'How does expert parallelism differ from tensor or pipeline parallelism, and why do MoE models need it?', 'Treating MoE like a standard dense model. Standard model parallelism splits every layer across devices, but MoE only activates a subset of experts per token, so static splitting wastes capacity.', 'In standard model parallelism (tensor/pipeline), every parameter is activated for every input and the model is split statically across devices. MoE models have a routing layer that sends each token to only k-of-N experts (e.g., 2 of 64). Expert parallelism places each expert on a different device and routes tokens dynamically via an all-to-all communication pattern. This is fundamentally different from tensor parallelism because: (1) each device runs a complete expert, not a slice of every layer, (2) communication is data-dependent (varies by routing decisions), and (3) load balancing across experts is critical — if routing is skewed, some GPUs are idle while others are overloaded.', 'Dense 64B model: every GPU activates all params. MoE 64×1B experts, top-2 routing: each token activates only 2B params, but tokens must be routed to the right GPU.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2711.yaml', 'e9f9e486643d1b0f00a07671e89b682dbfbd3b1696c924df028d5c6c0e8824b7', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2799', 'Cloud New 0014', 'data-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'create', 'training', 'published', 'Architect a privacy-preserving federated training system for a 1B language model across thousands of Cortex-M4 (168MHz, 256KB RAM) edge devices. Design the aggregation and training architecture.', 'How would you design federated training for a 1B language model across Cortex-M4 devices with 256KB RAM?', 'Attempting full parameter fine-tuning or sending full gradients over the edge network, instantly OOMing the 256KB RAM Cortex-M4 devices.', 'Architect a LoRA (Low-Rank Adaptation) based federated learning topology. The 1B base model is frozen and resides on a central cloud. The edge devices only receive and train ultra-small LoRA adapters (rank 4). Since 256KB RAM is extremely constrained, implement heavily quantized 8-bit gradients and gradient accumulation. Devices stream micro-updates asynchronously to a cloud aggregator, which uses secure multi-party computation to average the adapters before applying them to the global model.', '1B model = 2GB FP16 (impossible on 256KB). Rank 4 LoRA adapter for a single layer = 32KB. Cortex-M4 at 168MHz takes seconds for a single forward/backward pass of just the adapter layer. Async aggregation is mandatory to mask this.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2799.yaml', '167ef857d20ba20096c31c2523c386a17bece6aef4fd44b0b17c688c4d4d8ae9', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2807', 'Cloud New 0025', 'data-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'create', 'training', 'published', 'Architect an activation recomputation strategy to train a 200B parameter model on 128 A100 80GB GPUs. Prevent OOM errors while minimizing the compute overhead on the 312 TFLOPS hardware.', 'How would you design activation recomputation for a 200B model on 128 A100 80GB GPUs to avoid OOM with minimal overhead?', 'Checkpointing absolutely no activations and recomputing the entire forward pass natively, wasting almost 50% of your compute budget redundantly.', 'Design a selective activation recomputation architecture. Instead of recomputing all layers or completely discarding activations, profile the model to identify operators with high memory footprints but low compute intensity (e.g., LayerNorm, Dropout, Softmax). Discard these activations to save VRAM and recompute them on-the-fly during the backward pass. Retain the activations of heavy compute operators (like MatMuls) in HBM. Checkpoint only the boundaries of Transformer blocks.', '200B model across 128 GPUs requires complex 3D parallelism. Assuming DP=2, PP=8, TP=8. Softmax/LayerNorm activations consume ~30% of VRAM but only represent <2% of the 312 TFLOPS compute. Selective recomputation saves ~20GB VRAM per GPU.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2807.yaml', '71cd461e73f22c09716ee72939edf0f6bd77e7b6d2c1adf79e8aad6d6f56bc11', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3054', 'Pipeline Parallelism Bubble Overhead Comparison: GPipe vs PipeDream', 'pipeline-parallelism', 'cloud', 'L4', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'You are comparing GPipe and PipeDream-Flush scheduling on a 4-stage H100 pipeline (80GB HBM3, 3.35TB/s) with micro-batch size m=16. GPipe uses a synchronous flush after each mini-batch, while PipeDream-Flush uses 1F1B ordering. Calculate bubble overhead for each and recommend the approach for a 32B parameter model training run.', 'For a 4-stage H100 pipeline with 16 micro-batches, what are the GPipe and PipeDream-Flush bubble overheads, and which should train a 32B model?', 'Students often forget that GPipe bubble fraction is (p-1)/(m+p-1) where p=stages, m=micro-batches, and conflate stage count with device count.', 'GPipe bubble fraction = (4-1)/(16+4-1) = 3/19 ≈ 15.8%. PipeDream-Flush with 1F1B achieves same bubble fraction but with O(p) memory footprint instead of O(m) activations stored. For 32B model across 4 H100s (each 80GB), PipeDream-Flush is preferred because storing 16 micro-batch activations in GPipe requires ~16x per-stage activation memory.', 'Bubble overhead GPipe: 3/19 = 15.8%. Activation memory per micro-batch for 32B model: ~2 bytes/param * 32B = 64GB just for params, activations add ~1.5x = 96GB total per stage. With m=16, GPipe stores all 16 forward passes = 16 * activation_size before backward, likely OOM on 80GB H100. PipeDream-Flush stores max p=4 in-flight micro-batches, feasible at ~24GB activation budget per stage.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3054.yaml', '2978b0999bb89eba9543ee3a2b7f708ad8d17766a4747a4d1b5227b4e50e3383', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3427', 'Optimizing Pipeline Parallelism on NVIDIA A100 Clusters', 'pipeline-parallelism', 'cloud', 'L3', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'You are tasked with training a colossal 100-billion parameter language model using pipeline parallelism across a cluster equipped with NVIDIA A100 GPUs (each boasting 80 GB HBM2e memory, 312 TFLOPS FP16 peak performance, and 2.0 TB/s memory bandwidth). The model requires 8 pipeline stages. Initially, you consider a simple synchronous pipeline. Describe the inherent challenges this approach presents, particularly focusing on ''bubble overhead'' and its impact on A100 utilization. How would you quantify this overhead, and what advanced strategies, including micro-batching and interleaved schedules (like GPipe or PipeDream), would you employ to maximize the computational efficiency and throughput given the A100''s specific hardware characteristics?', 'How would you quantify bubble overhead in an 8-stage A100 pipeline and use micro-batching and interleaved schedules to improve throughput?', 'A common mistake is to overlook or significantly underestimate the ''bubble'' overhead in a synchronous pipeline, leading to substantial underutilization of the high-performance NVIDIA A100 GPUs. This often arises from assuming uniform stage execution times and not accounting for communication latency between GPUs and nodes, effectively wasting precious A100 FP16 TFLOPS and memory bandwidth.', 'The most effective solution involves implementing micro-batching combined with an interleaved pipeline schedule. By dividing the global batch into smaller micro-batches, computation can be overlapped with communication, significantly reducing bubble times. Profiling each pipeline stage on the A100 is crucial to identify bottlenecks (compute vs. memory bandwidth) and optimize stage partitioning. Techniques like asynchronous communication using NCCL (leveraging A100''s 2.0 TB/s HBM2e and NVLink capabilities) to hide data transfers, and dynamic micro-batch sizing, are critical to ensuring the A100''s 312 TFLOPS FP16 compute capacity is continuously engaged.', 'For a naive 8-stage synchronous pipeline where each stage takes ''T_stage'' milliseconds for a full batch, the total ''bubble'' time introduced per batch is (8 - 1) * T_stage = 7 * T_stage. If T_stage is, for instance, 200 ms, the bubble overhead is 1400 ms (1.4 seconds) per batch. To mitigate this, consider an interleaved schedule with ''M'' micro-batches. The pipeline fill-up and drain-out phases take approximately M + (N-1) micro-batch steps. How does this compare to the 7 * T_stage idle time in terms of overall pipeline efficiency for a given total batch processing time? Consider a single A100 doing FP16 operations: if a stage requires 10^14 FP16 operations, how long would it take given 312 TFLOPS peak performance?', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3427.yaml', 'fa91afcdb7a1d003be32e1132bc5caa8ce3e4bee16cd8d52f12f4f681db81f2d', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3429', 'Optimizing LLM Pipeline Parallelism on Google TPU v5e', 'pipeline-parallelism', 'cloud', 'L4', 'optimization', 'parallelism', 'analyze', 'training', 'published', 'You are deploying a large language model (LLM) with 500 billion parameters to a cluster of Google TPU v5e devices. Each TPU v5e has 16 GB HBM, 197 TFLOPS BF16 performance, and 1.6 TB/s memory bandwidth. To handle the model size, you''ve implemented pipeline parallelism, splitting the model into 8 stages across 8 distinct TPU v5e devices. Initial training runs show a significant underutilization of the TPUs, with observed device utilization averaging only 40%. You suspect ''pipeline bubbles'' are the primary culprit due to synchronous communication and idle periods. Describe how you would diagnose this bottleneck and propose a solution to improve throughput, quantifying the expected performance gain using the given TPU specs and assuming ideal conditions.', 'How would you diagnose TPU v5e pipeline bubbles in the 8-stage 500B model and quantify the throughput gain from micro-batching?', 'Ignoring the cumulative impact of inter-device communication latency and synchronous stage transitions, leading to significant idle time during pipeline bubbles. An inexperienced engineer might focus solely on optimizing individual stage computations or increasing the global batch size without adopting micro-batching strategies, which doesn''t address the fundamental bubble overhead.', 'Implement micro-batching combined with an interleaved scheduling strategy (e.g., a variant of GPipe or PipeDream). This allows different micro-batches from potentially different global batches to process concurrently within the pipeline, keeping the TPUs busy. Diagnosis would involve profiling each stage''s forward and backward pass times, and analyzing communication overheads between stages, potentially using tools like `tf.profiler` or custom logging to identify idle periods. Optimal micro-batch size selection is crucial, balancing memory usage, communication overhead, and bubble reduction.', 'Consider a pipeline with ''S'' stages (S=8) and a global batch processed into ''M'' micro-batches. In a naive synchronous schedule, the pipeline fill and drain phases create `(S-1)` periods of idle time equivalent to the critical path time for one micro-batch through a stage, `T_stage_critical`. If `T_stage_critical` is 100ms, the total bubble overhead for fill/drain is `7 * 100ms = 700ms`. If the ''active'' computation time for a global batch is, say, `10 * 100ms = 1000ms`, the total time would be `1700ms`. With interleaved scheduling, the `700ms` bubble time is largely overlapped with useful computation after the initial pipeline fill, effectively reducing the per-global-batch iteration time closer to 1000ms. This can lead to a throughput increase of approximately `1700ms / 1000ms = 1.7x`. If initial utilization is 40% (effective 0.4 * 197 TFLOPS = 78.8 TFLOPS/device), increasing utilization to 70% (0.7 * 197 TFLOPS = 137.9 TFLOPS/device) would represent a ~1.75x improvement in effective compute utilization due to reduced idle time.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3429.yaml', '18de72c51450c3463089b1b3a0300fe5c5f7d4436a94d3e30187e4a42481a831', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3431', 'Understanding 3D Parallelism with NVIDIA A100s for Frontier Models', '3d-parallelism', 'cloud', 'L2', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'You are leading a team training a frontier language model on a cluster equipped with NVIDIA A100 GPUs, each featuring 80 GB HBM2e memory, 312 TFLOPS of FP16 performance, and 2.0 TB/s of memory bandwidth. To achieve unprecedented scale and efficiently utilize these powerful accelerators, your architecture leverages 3D parallelism. Describe the distinct roles of data parallelism, tensor parallelism, and pipeline parallelism in this setup, specifically explaining how each component contributes to training a model that would otherwise be intractable on a single A100 GPU.', 'What roles do data, tensor, and pipeline parallelism play in training a frontier model across A100 GPUs?', 'A common mistake is to conflate the purposes of the different parallelism strategies, assuming they all address the same bottleneck. For example, relying solely on data parallelism when a model''s weights or activations exceed the 80 GB HBM2e memory capacity of a single NVIDIA A100, instead of employing tensor or pipeline parallelism, will inevitably lead to out-of-memory errors.', 'A realistic solution involves a strategic combination where: (1) Tensor parallelism horizontally partitions very large tensors (e.g., large weight matrices or activation tensors) across multiple A100 GPUs, effectively making a single ''logical'' GPU with a combined 160 GB, 240 GB, etc., of HBM2e memory. (2) Pipeline parallelism vertically partitions the model''s layers across A100 GPUs, allowing different layers to compute concurrently on different devices and hiding communication latency. (3) Data parallelism then replicates these tensor/pipeline-parallel instances and distributes mini-batches of data, scaling the overall throughput. The high 2.0 TB/s memory bandwidth of the A100s is crucial for efficient intra-node communication in both tensor and pipeline parallelism.', 'If a single model layer''s activation memory footprint is 180 GB, and an NVIDIA A100 GPU has 80 GB HBM2e, what is the minimum number of A100 GPUs required for just this layer using only tensor parallelism, assuming perfect partitioning?', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3431.yaml', '5863f1cadfc4e48c701dcd93d411cc13583cabd97ec1b08dd57332240af0c4e3', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3449', 'Multi-Tenant Resource Orchestration on Google TPU v5e for AI Workloads', 'scheduling-resource-management', 'cloud', 'L6+', 'mastery', 'parallelism', 'analyze', 'inference', 'published', 'Imagine you are designing the resource scheduler for a multi-tenant AI platform in Google Cloud, where diverse machine learning workloads (training, inference, batch processing) need to share a pool of Google TPU v5e devices. Each TPU v5e offers 16 GB HBM, 197 TFLOPS BF16 peak performance, and 1.6 TB/s memory bandwidth. Your platform hosts critical real-time inference services alongside large-scale, distributed training jobs. Users expect strict latency SLAs for inference and predictable training completion times, but resource contention is frequent.

How would you design a scheduling and resource management system that effectively leverages the TPU v5e''s capabilities and manages its constraints? Consider strategies for:
1.  **Resource Partitioning**: How would you virtually slice or dedicate parts of a TPU v5e to different tenants or workloads, given its fixed HBM and processing units? (Relate to MIG/MPS concepts, but for TPUs).
2.  **Workload Prioritization & Preemption**: How would you handle high-priority inference requests interrupting lower-priority training jobs without causing significant state loss or performance degradation?
3.  **Gang Scheduling**: For distributed training jobs requiring multiple TPU cores, how would you ensure all necessary resources are allocated simultaneously to avoid deadlocks or underutilization?
4.  **Multi-tenancy isolation**: What mechanisms would you implement to ensure performance isolation and security between different tenants'' workloads?
5.  **Scaling and Elasticity**: How would your system adapt to fluctuating demand, dynamically allocating and deallocating TPU resources?

Illustrate your design with specific considerations for the TPU v5e architecture, including potential bottlenecks and how to mitigate them. Justify your choices with quantitative reasoning where possible.', 'How would you design a scheduling and resource management system that effectively leverages the TPU v5e''s capabilities and manages its constraints?', 'A common mistake is applying generic CPU/GPU scheduling heuristics directly without accounting for the specific architecture and inter-core communication patterns of TPUs. For instance, treating HBM as a simple flat memory space rather than a critical, bandwidth-limited resource, or failing to address the synchronous nature of SPMD execution which can be impacted by naive preemption.', 'A robust solution would involve a hierarchical scheduler. At the cluster level, a scheduler would orchestrate job placement based on overall resource availability and job requirements (e.g., gang scheduling for multi-core training). At the device level, a specialized TPU-aware scheduler would manage micro-partitions, leveraging techniques like time-slicing (if supported, or mimicking with rapid context switching for inference) and explicit resource reservation (similar to MPS, but adapted for TPU slices). Fine-grained preemption for inference could involve saving and restoring model weights and optimizer states, potentially using snapshotting to HBM or host memory for faster recovery. Effective multi-tenancy would require strict resource quotas, potentially using software-defined resource isolation for memory and compute, alongside careful placement to minimize interference. The system would need a robust monitoring and feedback loop to dynamically adjust scheduling policies based on observed performance and resource utilization.', 'An inference model requires 4 GB HBM and performs 60 TFLOPS (BF16). A batch training job needs 8 GB HBM and 120 TFLOPS (BF16).
1.  What''s the maximum number of inference models that can *concurrently* reside in HBM on a single Google TPU v5e (16 GB HBM)? (16 GB / 4 GB = 4 models).
2.  If one inference model is running, what''s the peak BF16 TFLOPS remaining for training on the same TPU? (197 TFLOPS - 60 TFLOPS = 137 TFLOPS).
3.  If a training checkpoint of 10 GB needs to be loaded into HBM, what''s the theoretical minimum time assuming constant 1.6 TB/s HBM bandwidth? (10 GB / (1.6 TB/s * 1024 GB/TB) = 10 GB / 1638.4 GB/s ≈ 0.006 seconds). This highlights that HBM bandwidth is very high, and external factors like host transfer or computation are usually the bottleneck.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3449.yaml', 'b667103e068438b558474f920c1fbc7215357e8b2e1973d71342f3f49311dd53', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3927', 'Pipeline Bubble Minimization via 1F1B Scheduling', 'communication-computation-overlap', 'cloud', 'L4', 'fluency', 'parallelism', 'understand', 'both', 'published', 'Your 4-stage pipeline-parallel training of a 70B model has a pipeline bubble at the end of each micro-batch cycle. With 4 stages and 8 micro-batches, the GPipe schedule wastes significant GPU time in bubble periods. A colleague suggests switching to the 1F1B (one-forward-one-backward) schedule.', 'How does switching from GPipe to 1F1B change the bubble fraction and activation memory for 4 stages and 8 micro-batches?', 'Thinking 1F1B eliminates the pipeline bubble entirely. It reduces the bubble from O(k-1) micro-batches (where k is the number of stages) to a startup phase, but a bubble still exists during the warm-up and cool-down phases.', 'GPipe: all forwards first, then all backwards. Bubble = (k-1) micro-batch times at the end = (4-1) x t = 3t. 1F1B: after the warm-up phase (k-1 forward passes), alternate one forward and one backward per step. Bubble only during warm-up (k-1 forward passes) and cool-down (k-1 backward passes). For m micro-batches and k stages: GPipe bubble fraction = (k-1)/m. 1F1B bubble fraction = (k-1)/(m + k-1). With k=4, m=8: GPipe = 3/8 = 37.5% bubble. 1F1B = 3/11 = 27.3% bubble. Additionally, 1F1B reduces peak memory from O(m) to O(k) by freeing activations earlier.', '70B model, 4 stages. Each micro-batch forward+backward per stage: ~200ms. GPipe total: (8 + 3) x 200ms = 2200ms, bubble = 600ms (27%). 1F1B total: (8 + 3) x 200ms = 2200ms (same total, but memory reduced from 8x to 4x activation storage).', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3927.yaml', 'a4c412cfc531258462468ed1e5430f378476e2bba6f5ac19daffafaaf5b6e9a7', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3930', 'Overlap Efficiency Degradation at Scale: 8 GPUs vs 256 GPUs', 'communication-computation-overlap', 'cloud', 'L5', 'diagnosis', 'parallelism', 'analyze', 'both', 'published', 'Your DDP training achieves 92% overlap efficiency at 8 H100 GPUs (single node, NVLink) but only 68% at 256 H100 GPUs (32 nodes, InfiniBand). AllReduce time grows faster than expected. Diagnose why overlap degrades at scale.', 'Why does AllReduce overlap efficiency fall from 92% at 8 H100s to 68% at 256 H100s, and how would you fix it?', 'Assuming AllReduce time scales linearly with node count. Ring AllReduce time is 2(n-1)/n x M/B (nearly constant for large n), but in practice, cross-node AllReduce has much higher latency than intra-node NVLink AllReduce.', 'Three factors degrade overlap at 256 GPUs: (1) AllReduce latency increases: intra-node NVLink ring at 900 GB/s vs inter-node IB at 50 GB/s per link. For 5.2GB gradients: NVLink AllReduce ~6ms, IB AllReduce ~104ms. The 104ms AllReduce exceeds the backward pass time, making overlap impossible. (2) Network congestion: 32 nodes doing simultaneous AllReduce creates IB fabric contention, adding 10-30% overhead. (3) Bucket synchronization: 256 processes must synchronize bucket readiness, adding coordination latency. Fix: use hierarchical AllReduce (intra-node reduce first via NVLink, then inter-node AllReduce of reduced results). This cuts inter-node traffic by 8x.', 'Hierarchical AR: Step 1: 8-GPU reduce-scatter on NVLink, 5.2GB / 8 = 650MB per GPU. Step 2: inter-node AllReduce of 650MB at 50 GB/s = 13ms. Step 3: intra-node all-gather, ~1ms. Total: ~14ms vs flat AllReduce 104ms. Overlap at 14ms becomes feasible against a 200ms backward pass.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3930.yaml', 'f6044fc95c8a870bf8003db09c135f9b103754b967198c81e16bbe41b1ef0b8a', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3931', 'Tensor Parallelism AllReduce Overlap with Feedforward Computation', 'communication-computation-overlap', 'cloud', 'L4', 'fluency', 'parallelism', 'understand', 'both', 'published', 'In tensor-parallel training of a 70B LLM across 8 H100 GPUs (NVLink), each transformer layer requires two AllReduce operations: one after the attention block and one after the MLP block. These AllReduces are on the critical path. Can they be overlapped with computation?', 'Can they be overlapped with computation?', 'Assuming tensor parallelism AllReduces can be overlapped like DDP gradient AllReduces. In tensor parallelism, the AllReduce output is the input to the next computation — there is a strict data dependency.', 'Standard tensor parallelism AllReduces cannot be overlapped because each produces a partial sum that is needed before the next layer starts. However, two techniques partially address this: (1) Async ReduceScatter + AllGather decomposition: split AllReduce into ReduceScatter (output partial results while computing) + AllGather (reconstruct while starting next layer''s computation). The AllGather can partially overlap with the next layer''s input processing. (2) Sequence parallelism: overlap the sequence dimension''s AllGather with computation by processing received chunks as they arrive. Megatron-LM uses this to overlap 30-40% of communication.', '70B model, 8-way TP, 96 layers. Each layer: 2 AllReduces of ~160MB (hidden_size=8192, seq_len=2048, BF16). NVLink 900 GB/s: 160MB/900 = 0.18ms per AllReduce. 192 AllReduces x 0.18ms = 34.5ms total. Compute per layer: ~5ms. Communication is 7% of compute — small enough that partial overlap via sequence parallelism recovers most of it.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3931.yaml', '8d6ec5be68aacbf68983d0beb19748ad8d264a12534790cf8785a955d71a2f64', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-4047', 'Gradient Synchronization for ZeRO Stage 3', 'gradient-synchronization', 'cloud', 'L5', 'design', 'parallelism', 'create', 'training', 'published', 'ZeRO Stage 3 partitions model parameters, gradients, and optimizer states across GPUs. Unlike standard data parallelism where each GPU holds a full copy, each GPU only holds 1/N of everything. This means forward/backward passes require all-gather of parameters before each layer and reduce-scatter of gradients after. Design the communication schedule for a 64-MI300X cluster training a 30B parameter model with 60 Transformer layers.', 'What is the ZeRO-3 per-layer communication schedule and cost for a 64-MI300X, 30B-parameter, 60-layer training run?', 'Thinking ZeRO-3 only does one AllReduce per iteration like standard data parallelism. ZeRO-3 does per-layer all-gather and reduce-scatter, creating 2L communication events per iteration (L all-gathers in forward, L reduce-scatters in backward) — trading peak memory for communication volume.', 'Model: 30B params = 60GB FP16. Per GPU (64 GPUs): 60GB/64 = 937.5MB of parameters, gradients, and optimizer states (vs 60GB full copy). Communication per layer: Forward: all-gather 30B/60 layers = 500M params × 2 bytes = 1GB per layer. 60 all-gathers in forward. Backward: all-gather same 1GB per layer (parameters needed again). 60 all-gathers in backward. Gradient reduce-scatter: same 1GB per layer. 60 reduce-scatters in backward. Total communication: 3 × 60 × 2 × 63/64 × 1GB / 50GB/s = 7,087ms without overlap. With prefetching overlap: pipeline all-gather for layer L+1 during computation of layer L. Each all-gather: 2 × 63/64 × 1GB / 50GB/s = 39.4ms. Layer compute: ~5ms. Communication is 7.9× slower — use all 8 NICs on MI300X (8 × 400Gbps): all-gather = 4.9ms ≈ compute (5ms), near-perfect overlap.', 'Memory savings: 60GB (full copy) → 937.5MB (ZeRO-3) per GPU = 64× reduction. Communication cost: ZeRO-3 requires 3 collectives per layer (all-gather for forward, all-gather for backward, reduce-scatter for gradients): 3 × 60 layers × 1GB = 180GB per iteration (vs 60GB single AllReduce for standard data parallel). 3× more communication volume but per-layer pipelining hides it behind compute if NIC bandwidth ≥ compute intensity.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-4047.yaml', 'f3f15f4b6b405a7cf7f8596a6f35fd7eb0ee4953f89dc8478f3b26b6731f021a', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-4087', 'Row-Parallel vs Column-Parallel Weight Splitting', 'model-tensor-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'understand', 'training', 'published', 'Explain the difference between column-parallel and row-parallel linear layers in Megatron-LM. For a weight matrix W of shape [H_in, H_out] split across 4 GPUs, what does each GPU hold, and what collective is needed after each?', 'For a weight matrix W of shape [H_in, H_out] split across 4 GPUs, what does each GPU hold, and what collective is needed after each?', 'Mixing up which dimension is split. Column-parallel splits along H_out (each GPU gets full H_in but H_out/4). Row-parallel splits along H_in (each GPU gets H_in/4 but full H_out).', 'Column-parallel: W is split along columns (output dimension). Each GPU holds W_i of shape [H_in, H_out/4]. Input x is replicated on all GPUs. Each GPU computes y_i = x @ W_i, producing shape [batch, H_out/4]. An AllGather concatenates these into the full [batch, H_out]. Row-parallel: W is split along rows (input dimension). Each GPU holds W_i of shape [H_in/4, H_out]. Input x must be split: each GPU gets x_i of shape [batch, H_in/4]. Each GPU computes y_i = x_i @ W_i, producing a partial sum of shape [batch, H_out]. An AllReduce sums these partials into the final result. Megatron pairs column→row to eliminate one collective: the column output is already naturally partitioned to serve as row input.', 'For H_in=H_out=8192, TP=4: Column-parallel shards are [8192, 2048] (8192×2048 = 16.78M params). Row-parallel shards are [2048, 8192] (16.78M params). Both are 16.78M params × 2B = 33.6 MB per GPU.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-4087.yaml', '586d932a1fc764877c45f1424239235fb90f8170228fca032e8a69a1b5e76c06', NULL);
